type AppEmptyStateOptions = Omit<Parameters<typeof richEmptyState>[0], 'message'>;

function renderEmptyState(message: string, opts: AppEmptyStateOptions = {}): string {
  return richEmptyState({
    title: 'Nog niets vastgelegd',
    ...opts,
    message,
  });
}

