function renderScreenContent(activeId: ScreenId, screen: Screen, state: AppShellState): string {
  if (activeId === 'start') return renderStartScreen(state);
  if (activeId === 'traject') return renderTrajectScreen(state);
  if (activeId === 'agenda') return renderAgendaScreen(state);
  if (activeId === 'medicatie') return renderMedicatieScreen(state);
  if (activeId === 'herinneringen') return renderHerinneringenScreen(state);
  if (activeId === 'vragen') return renderVragenScreen(state);
  if (activeId === 'dossier') return renderDossierScreen(state);
  if (activeId === 'kennis') return renderKennisScreen(state);
  if (activeId === 'welzijn') return renderWelzijnScreen(state);
  if (activeId === 'afwegingen') return renderAfwegingenScreen(state);
  if (activeId === 'kosten') return renderKostenScreen(state);
  if (activeId === 'logboek') return renderLogboekScreen(state);
  if (activeId === 'backup') return renderBackupScreen(state);

  return `
    <section class="section-stack" aria-label="${screen.label}">
      <div class="summary-panel">
        <h2>Volgende stap</h2>
        <p>${screen.emptyState}</p>
      </div>
      ${renderPolicyPanel()}
    </section>
  `;
}

function renderLogboekScreen(state: AppShellState): string {
  const logs = state.eventLogs ?? [];
  const highRiskLogs = logs.filter(isHighRiskEventLogForUi);
  const categoryCounts = logs.reduce<Record<EventLog['categorie'], number>>(
    (counts, item) => {
      counts[item.categorie] = (counts[item.categorie] ?? 0) + 1;
      return counts;
    },
    {} as Record<EventLog['categorie'], number>,
  );
  const body = isCentralStorage(state)
    ? `Dit logboek staat in je centrale versleutelde opslag en toont alleen privacyrelevante gebeurtenisdetails. ${logs.length} gebeurtenis${logs.length === 1 ? '' : 'sen'} vastgelegd.`
    : `Dit logboek blijft in de lokale kluis op dit toestel. ${logs.length} gebeurtenis${logs.length === 1 ? '' : 'sen'} vastgelegd.`;
  const activeEventLogRoute = state.activeEventLogRoute ?? 'overzicht';

  const eventLogWorkbench = renderEventLogSystemWorkbench({
    eventCount: logs.length,
    highRiskCount: highRiskLogs.length,
    categoryCount: Object.keys(categoryCounts).length,
    central: isCentralStorage(state),
    latestLog: logs[0],
  });
  const eventLogWorkspace = domainSplitWorkspace({
    className: 'eventlog-split-workspace',
    ariaLabel: 'Logboek split-view werkruimte',
    data: {
      'eventlog-split-workspace': 'ready',
      'eventlog-compact-workspace': 'route-first',
      'eventlog-single-workspace': 'ready',
    },
    rail: renderEventLogTaskRoutes({
      eventCount: logs.length,
      highRiskCount: highRiskLogs.length,
      categoryCount: Object.keys(categoryCounts).length,
      central: isCentralStorage(state),
      activeRoute: activeEventLogRoute,
    }),
    context: eventLogWorkbench,
    main: `
      <section id="logboek-route-overzicht" class="eventlog-route-section" aria-labelledby="logboek-route-overzicht-title" data-eventlog-route="overzicht"${renderEventLogRouteVisibility(activeEventLogRoute, 'overzicht')}>
        <header class="eventlog-route-section__header">
          <p class="kp-card__eyebrow">Overzicht</p>
          <h2 id="logboek-route-overzicht-title">Logboekstatus</h2>
          <p>Controleer opslagmodus en privacyrisico's zonder gevoelige gebeurtenisdetails te tonen.</p>
        </header>
        ${commandRouteSummary({
          eyebrow: 'Logboekroute',
          title: 'Eerst auditstatus scannen',
          detail:
            'Opslagmodus, eventaantal en privacyrisico blijven direct zichtbaar; auditregels open je pas in de detailroutes.',
          primary: { href: '#logboek-route-recent', label: 'Recent' },
          secondary: { href: '#logboek-route-privacy', label: 'Privacy' },
          status: `${logs.length} events`,
          ariaLabel: 'Logboek overzicht route-samenvatting',
          data: { 'eventlog-route-summary': 'overzicht' },
        })}
        ${card({
          title: 'Gebeurtenissen',
          body: `<p data-event-log-storage="${isCentralStorage(state) ? 'central-encrypted-dataset' : 'legacy-local-vault'}" data-event-log-state="${logs.length > 0 ? 'active' : 'empty'}" data-event-log-high-risk="${highRiskLogs.length > 0 ? 'present' : 'none'}">${body}</p>`,
        })}
      </section>
      <section id="logboek-route-recent" class="eventlog-route-section" aria-labelledby="logboek-route-recent-title" data-eventlog-route="recent"${renderEventLogRouteVisibility(activeEventLogRoute, 'recent')}>
        <header class="eventlog-route-section__header">
          <p class="kp-card__eyebrow">Recent</p>
          <h2 id="logboek-route-recent-title">Recente gebeurtenissen</h2>
          <p>Lees de laatste lokale auditregels terug in tijdsvolgorde.</p>
        </header>
        ${commandRouteSummary({
          eyebrow: 'Logboekroute',
          title: 'Auditregels pas openen wanneer je ze nodig hebt',
          detail:
            'Recente gebeurtenissen blijven volledig terugleesbaar, maar staan achter één openactie tegen logboekstapeling.',
          primary: { href: '#logboek-recent-disclosure', label: 'Events openen' },
          secondary: { href: '#logboek-route-categorieen', label: 'Categorieën' },
          status: `${logs.length} events`,
          ariaLabel: 'Logboek recent route-samenvatting',
          data: { 'eventlog-route-summary': 'recent' },
        })}
        <details id="logboek-recent-disclosure" class="kp-disclosure" data-eventlog-disclosure="recent">
          <summary class="kp-disclosure__summary">Recente auditregels openen</summary>
          <div class="kp-disclosure__body">
            ${
              logs.length > 0
                ? renderEventLogTimeline(logs, 'recent')
                : renderEmptyState('Nog geen gebeurtenissen vastgelegd.', {
                    title: 'Logboek is nog leeg',
                  })
            }
          </div>
        </details>
      </section>
      <section id="logboek-route-categorieen" class="eventlog-route-section" aria-labelledby="logboek-route-categorieen-title" data-eventlog-route="categorieen"${renderEventLogRouteVisibility(activeEventLogRoute, 'categorieen')}>
        <header class="eventlog-route-section__header">
          <p class="kp-card__eyebrow">Categorieën</p>
          <h2 id="logboek-route-categorieen-title">Categorieën scannen</h2>
          <p>Bekijk hoeveel gebeurtenissen per categorie zijn vastgelegd.</p>
        </header>
        ${commandRouteSummary({
          eyebrow: 'Logboekroute',
          title: 'Categorieën als compacte auditkaart',
          detail:
            'Categorieaantallen staan achter een disclosure zodat het logboek niet direct alle systeemdetails toont.',
          primary: { href: '#logboek-categorieen-disclosure', label: 'Categorieën openen' },
          status: `${Object.keys(categoryCounts).length} soorten`,
          ariaLabel: 'Logboek categorieën route-samenvatting',
          data: { 'eventlog-route-summary': 'categorieen' },
        })}
        <details id="logboek-categorieen-disclosure" class="kp-disclosure" data-eventlog-disclosure="categorieen">
          <summary class="kp-disclosure__summary">Categorieaantallen openen</summary>
          <div class="kp-disclosure__body">
            ${renderEventLogCategorySummary(categoryCounts)}
          </div>
        </details>
      </section>
      <section id="logboek-route-privacy" class="eventlog-route-section" aria-labelledby="logboek-route-privacy-title" data-eventlog-route="privacy"${renderEventLogRouteVisibility(activeEventLogRoute, 'privacy')}>
        <header class="eventlog-route-section__header">
          <p class="kp-card__eyebrow">Privacy</p>
          <h2 id="logboek-route-privacy-title">Privacygevoelige gebeurtenissen</h2>
          <p>Controleer welke auditregels extra terughoudend worden weergegeven.</p>
        </header>
        ${commandRouteSummary({
          eyebrow: 'Logboekroute',
          title: 'Privacyregels apart controleren',
          detail:
            'De privacycontrole staat vooraan. Auditregels en routecontext open je pas als vervolgcontext.',
          primary: { href: '#eventlog-privacy-primary', label: 'Privacycontrole' },
          secondary: { href: '#logboek-privacy-disclosure', label: 'Vervolgcontext' },
          status: `${highRiskLogs.length} signalen`,
          ariaLabel: 'Logboek privacy route-samenvatting',
          data: { 'eventlog-route-summary': 'privacy' },
        })}
        <div class="eventlog-privacy-console" data-eventlog-privacy-layout="single-check">
          <div id="eventlog-privacy-primary" class="summary-panel eventlog-privacy-primary" data-eventlog-privacy-primary="control">
            <h3>Privacycontrole</h3>
            <p class="small-print">Controleer alleen opslagmodus en risicosignalen. Kiempad toont geen trackingpayload, plaintext medische inhoud of besluitvormende medische inhoud.</p>
            <dl class="summary-list">
              <div><dt>Opslag</dt><dd>${isCentralStorage(state) ? 'Centraal versleuteld' : 'Lokale kluis'}</dd></div>
              <div><dt>Privacysignalen</dt><dd>${highRiskLogs.length}</dd></div>
              <div><dt>Auditregels</dt><dd>${logs.length}</dd></div>
            </dl>
          </div>
          <details id="logboek-privacy-disclosure" class="kp-disclosure eventlog-privacy-followup" data-eventlog-disclosure="privacy" data-eventlog-privacy-followup="collapsed">
            <summary class="kp-disclosure__summary eventlog-privacy-followup__summary">
              <span>
                <strong>Privacygevoelige auditregels openen</strong>
                <small>Bekijk auditregels, recent overzicht of categorieën pas na de privacycontrole.</small>
              </span>
              <em>${highRiskLogs.length} signalen</em>
            </summary>
            <div class="kp-disclosure__body eventlog-privacy-followup__body">
              <nav class="eventlog-privacy-followup__links" aria-label="Logboek privacy vervolgcontext">
                <a href="#logboek?route=recent">Recente auditregels</a>
                <a href="#logboek?route=categorieen">Categorieën</a>
                <a href="#logboek?route=overzicht">Logboekstatus</a>
              </nav>
              ${
                highRiskLogs.length > 0
                  ? renderEventLogTimeline(highRiskLogs, 'privacy')
                  : renderEmptyState('Geen privacygevoelige gebeurtenissen in dit logboek.', {
                      title: 'Geen privacyregels',
                    })
              }
            </div>
          </details>
        </div>
      </section>
        `,
  });

  return sectionStack(
    [
      renderEventLogFocusShell({
        workspace: eventLogWorkspace,
      }),
    ],
    {
      className: 'eventlog-command-layout',
      ariaLabel: isCentralStorage(state) ? 'Gebeurtenissenlog' : 'Lokaal gebeurtenissenlog',
    },
  );
}

