function renderEventLogTaskRoutes(input: {
  eventCount: number;
  highRiskCount: number;
  categoryCount: number;
  central: boolean;
  activeRoute: EventLogRoute;
}): string {
  const routes: readonly CommandTaskRoute<EventLogRoute>[] = [
    {
      id: 'overzicht',
      href: '#logboek?route=overzicht',
      label: 'Overzicht',
      meta: input.central ? 'centraal' : 'lokaal',
      badge: input.central ? 'centraal' : 'lokaal',
      density: 'filled',
    },
    {
      id: 'recent',
      href: '#logboek?route=recent',
      label: 'Recent',
      meta: `${input.eventCount} events`,
      badge: String(input.eventCount),
      density: input.eventCount > 0 ? 'filled' : 'empty',
    },
    {
      id: 'categorieen',
      href: '#logboek?route=categorieen',
      label: 'Categorieën',
      meta: `${input.categoryCount} soorten`,
      badge: String(input.categoryCount),
      density: input.categoryCount > 0 ? 'filled' : 'empty',
    },
    {
      id: 'privacy',
      href: '#logboek?route=privacy',
      label: 'Privacy',
      meta: `${input.highRiskCount} signalen`,
      badge: String(input.highRiskCount),
      density: input.highRiskCount > 0 ? 'action' : 'empty',
    },
  ];

  return renderCommandTaskRoutes({
    className: 'eventlog-task-routes',
    routeClassName: 'eventlog-task-route',
    ariaLabel: 'Logboek taakroutes',
    dataAttribute: 'eventlog-task-routes',
    routes,
    activeRoute: input.activeRoute,
  });
}

function renderEventLogRouteVisibility(activeRoute: EventLogRoute, route: EventLogRoute): string {
  return route === activeRoute
    ? ' data-eventlog-route-state="active"'
    : ' data-eventlog-route-state="inactive" hidden';
}

function renderEventLogCategorySummary(
  counts: Partial<Record<EventLog['categorie'], number>>,
): string {
  const entries = Object.entries(counts) as [EventLog['categorie'], number][];
  if (entries.length === 0)
    return renderEmptyState('Nog geen categorieën vastgelegd.', { title: 'Geen categorieën' });

  return `
    <dl class="summary-list">
      ${entries
        .map(
          ([categorie, count]) => `
            <div data-eventlog-category="${escapeAttribute(categorie)}">
              <dt>${escapeHtml(EVENT_CATEGORIE_LABELS[categorie])}</dt>
              <dd>${count} gebeurtenis${count === 1 ? '' : 'sen'}</dd>
            </div>
          `,
        )
        .join('')}
    </dl>
  `;
}

function renderEventLogTimeline(items: readonly EventLog[], scope: 'recent' | 'privacy'): string {
  return timelineList({
    className: 'eventlog-timeline',
    ariaLabel:
      scope === 'privacy'
        ? 'Privacygevoelige auditregels als tijdlijn'
        : 'Recente auditregels als tijdlijn',
    data: {
      'eventlog-timeline': scope,
      'eventlog-timeline-state': items.length > 0 ? 'gevuld' : 'leeg',
    },
    items: items.map((item, index) => renderEventLogItem(item, scope, index)),
  });
}

function renderEventLogItem(item: EventLog, scope: 'recent' | 'privacy', index: number): string {
  const detail = item.detail;
  const safeDetail =
    detail &&
    isEventLogDetailPrivacySafe(item) &&
    !EVENT_LOG_UI_SENSITIVE_DETAIL_PATTERNS.some((pattern) => pattern.test(detail))
      ? detail
      : undefined;
  const highRisk = isHighRiskEventLogForUi(item);
  const state = (highRisk ? 'missed' : index === 0 ? 'current' : 'done') as StepState;
  const privacyLabel = highRisk ? 'Privacygevoelig' : 'Minimale details';
  const storageLabel = item.categorie === 'backup' ? 'Versleuteld beheer' : 'Auditmetadata';
  const body = `
    <dl class="eventlog-timeline__facts">
      <div>
        <dt>Privacy</dt>
        <dd>${privacyLabel}</dd>
      </div>
      <div>
        <dt>Opslag</dt>
        <dd>${storageLabel}</dd>
      </div>
    </dl>
    ${
      safeDetail
        ? `<p class="eventlog-timeline__safe-detail">${escapeHtml(safeDetail)}</p>`
        : `<p class="eventlog-timeline__safe-detail">Detail blijft verborgen: deze auditregel toont alleen veilige metadata.</p>`
    }
  `;

  return timelineItem({
    title: item.gebeurtenis,
    meta: `${formatDateTime(item.datum)} · ${EVENT_CATEGORIE_LABELS[item.categorie]}`,
    detail: scope === 'privacy' ? 'Extra terughoudend weergegeven.' : undefined,
    state,
    className: 'eventlog-timeline__item',
    data: {
      'eventlog-item-category': item.categorie,
      'eventlog-item-privacy': highRisk ? 'high' : 'normal',
      'eventlog-item-scope': scope,
    },
    body,
  });
}

const EVENT_LOG_UI_SENSITIVE_DETAIL_PATTERNS = [
  /\btoken\b/i,
  /\bpassphrase\b/i,
  /\bapi[-_\s]?sleutel\b/i,
  /\bapi[-_\s]?key\b/i,
  /\bproviderpayload\b/i,
  /\bprovider[-_\s]?payload\b/i,
  /\bwebauthn\b/i,
  /\bprf\b/i,
  /\bencrypted\s+dataset\b/i,
  /\blegacy\s+lokale\s+kluis\b/i,
  /\bbestandsinhoud\b/i,
  /\bfile[-_\s]?contents\b/i,
  /\bbase64\b/i,
  /\bencrypted[-_\s]?payload\b/i,
  /\bocr[-_\s]?payload\b/i,
  /\battachment[-_\s]?payload\b/i,
  /\brecord[-_\s]?payload\b/i,
  /\bdossierpayload\b/i,
  /\bdossier\s+payload\b/i,
  /\bdiagnose\b/i,
  /\bbehandelkeuzeadvies\b/i,
  /\b[\w.-]+\.(?:pdf|jpg|jpeg|png|heic|json|kiempad-export|kiempad-sync)\b/i,
  /\b\d+([,.]\d+)?\s?(mg|mcg|µg|iu|ml)\b/i,
];

function isHighRiskEventLogForUi(item: EventLog): boolean {
  const gebeurtenis = item.gebeurtenis.toLowerCase();
  return (
    item.categorie === 'backup' ||
    item.categorie === 'ai' ||
    gebeurtenis.includes('import') ||
    gebeurtenis.includes('geïmporteerd') ||
    gebeurtenis.includes('notificatie') ||
    gebeurtenis.includes('melding')
  );
}

