function renderKnowledgeResearchReader(input: {
  sources: number;
  scientific: number;
  patient: number;
  relevance: number;
  relations: number;
  trends: number;
}): string {
  const lanes = [
    {
      id: 'scientific',
      href: '#knowledge-research-summaries',
      label: 'Wetenschappelijk',
      title: `${input.scientific} samenvatting${input.scientific === 1 ? '' : 'en'}`,
      detail: 'Methode, bevindingen en beperkingen blijven brongekoppeld.',
      cue: 'Bronnen volgen',
    },
    {
      id: 'patient',
      href: '#knowledge-research-summaries',
      label: 'Eenvoudig',
      title: `${input.patient} uitleg${input.patient === 1 ? '' : 'en'}`,
      detail: 'Gewone taal per publicatie voordat je dieper leest.',
      cue: 'Lekenlaag',
    },
    {
      id: 'relevance',
      href: '#knowledge-research-trends',
      label: 'Relevantie',
      title: `${input.relevance} contextnotitie${input.relevance === 1 ? '' : 's'}`,
      detail: 'Bespreekcontext naast jullie dossier, geen behandeladvies.',
      cue: 'Kliniekvragen',
    },
    {
      id: 'trends',
      href: '#knowledge-research-trends',
      label: 'Trends',
      title: `${input.trends} groep${input.trends === 1 ? '' : 'en'}`,
      detail: `${input.relations} relaties en ${input.sources} bronnen voor snelle scan.`,
      cue: 'Signalen scannen',
    },
  ];

  return `
    <details class="knowledge-research-reader knowledge-research-lane-choice" aria-label="Research leeslaag" data-knowledge-research-reader="ready" data-knowledge-research-lane-choice="collapsed">
      <summary class="knowledge-research-lane-choice__summary">
        <span>
          <small>Leeslaag</small>
          <strong>Researchlaag openen</strong>
        </span>
        <em>${input.sources} bronnen</em>
      </summary>
      <div class="knowledge-research-lane-choice__body">
        <header class="knowledge-research-reader__header">
          <div>
            <p class="kp-card__eyebrow">Leeslaag</p>
            <h3>Kies eerst je researchlaag</h3>
          </div>
          <p>Start met de laag die past bij je vraag; bronnen, samenvattingen en trends blijven daarna uitklapbaar.</p>
        </header>
        <nav class="knowledge-research-reader__lanes" aria-label="Researchlaag kiezen">
        ${lanes
          .map(
            (lane) => `
        <a class="knowledge-research-reader__lane" href="${lane.href}" data-knowledge-research-lane="${lane.id}">
          <span>${lane.label}</span>
          <strong>${lane.title}</strong>
          <small>${lane.detail}</small>
          <em>${lane.cue}</em>
        </a>`,
          )
          .join('')}
        </nav>
        <p class="small-print">Kiempad toont hier geen dossierplaintext of OCR-tekst en geeft geen behandeladvies; gebruik de lagen als voorbereiding op gesprek met je kliniek.</p>
      </div>
    </details>
  `;
}

function renderKnowledgeResearchWorkbench(input: {
  researchBronnen: number;
  researchSamenvattingen: number;
  researchTrends: number;
  kennisItems: number;
  totalKennisItems: number;
  netwerkAan: boolean;
  filter: KennisFilter;
}): string {
  return `
    <section class="knowledge-research-workbench" aria-label="Researchwerkbank" data-knowledge-first-viewport="research-workbench">
      <header class="knowledge-research-workbench__header">
        <div>
          <p class="kp-card__eyebrow">Researchwerkbank</p>
          <h2>Research begrijpen zonder alles tegelijk te lezen</h2>
          <p>Start met publicaties, trends of broncontrole. Kiempad houdt research conceptmatig en brongekoppeld.</p>
        </div>
      </header>
      ${renderKnowledgeResearchSnapshot(input)}
      <div id="knowledge-overview" class="summary-panel priority-panel knowledge-command-panel">
        <div class="knowledge-command-panel__intro">
          <div>
            <h2>Kennisbank</h2>
            <p>Alle items zijn concept totdat een behandelaar ze bevestigt.</p>
          </div>
          ${renderKnowledgeWorkbenchStatusChoice(input)}
        </div>
        ${renderKennisFilterForm(input.filter)}
      </div>
    </section>
  `;
}

