function renderKnowledgeItemStatus(input: {
  kennisItems: number;
  totalKennisItems: number;
}): string {
  if (input.totalKennisItems === 0) {
    return renderEmptyState('Voeg een bron of eigen kennisitem toe om de bibliotheek te vullen.', {
      title: 'Nog geen kennisitems',
      cta: { href: '#kennis?route=add', label: 'Kennis toevoegen' },
    });
  }

  if (input.kennisItems === 0) {
    return renderEmptyState('Geen kennisitems passen bij dit filter.', {
      title: 'Geen filterresultaten',
      cta: { href: '#knowledge-filter-form', label: 'Filter aanpassen' },
    });
  }

  return `<p data-knowledge-visible-count="ready">${formatKnowledgeVisibleCount(input.kennisItems, input.totalKennisItems)}</p>`;
}

function formatKnowledgeVisibleCount(visible: number, total: number): string {
  if (total === 0) return 'Nog niets zichtbaar';
  if (visible === total) return `${total} kennisitem${total === 1 ? '' : 's'} zichtbaar`;
  return `${visible} van ${total} kennisitem${total === 1 ? '' : 's'} zichtbaar`;
}

function renderKennisTaskRoutes(input: {
  researchBronnen: number;
  researchSamenvattingen: number;
  researchTrends: number;
  kennisItems: number;
  activeRoute: KnowledgeRoute;
}): string {
  const routes: readonly CommandTaskRoute<KnowledgeRoute>[] = [
    {
      id: 'read',
      href: '#kennis?route=read',
      label: 'Research lezen',
      meta: `${input.researchBronnen} bronnen · ${input.researchSamenvattingen} samenvattingen`,
      badge: String(input.researchBronnen),
      density: input.researchBronnen > 0 ? 'filled' : 'empty',
    },
    {
      id: 'add',
      href: '#kennis?route=add',
      label: 'Toevoegen',
      meta: 'Research of kennisitem',
      badge: 'nieuw',
      density: 'action',
    },
    {
      id: 'ai',
      href: '#kennis?route=ai',
      label: 'AI & netwerk',
      meta: `${input.researchTrends} trendgroepen`,
      badge: String(input.researchTrends),
      density: input.researchTrends > 0 ? 'filled' : 'action',
    },
    {
      id: 'library',
      href: '#kennis?route=library',
      label: 'Bibliotheek',
      meta: `${input.kennisItems} items`,
      badge: String(input.kennisItems),
      density: input.kennisItems > 0 ? 'filled' : 'empty',
    },
  ];

  const activeRoute = routes.find((route) => route.id === input.activeRoute) ?? {
    id: 'read',
    href: '#kennis?route=read',
    label: 'Research lezen',
    meta: `${input.researchBronnen} bronnen · ${input.researchSamenvattingen} samenvattingen`,
    badge: String(input.researchBronnen),
    density: input.researchBronnen > 0 ? 'filled' : 'empty',
  };
  const routesMarkup = renderCommandTaskRoutes({
    className: 'knowledge-task-routes',
    routeClassName: 'knowledge-task-route',
    ariaLabel: 'Kennis taakroutes',
    dataAttribute: 'knowledge-task-routes',
    routes,
    activeRoute: input.activeRoute,
  });

  return `
    <details class="knowledge-task-route-choice" data-knowledge-task-route-choice="collapsed">
      <summary class="knowledge-task-route-choice__summary">
        <span>
          <strong>Kies kennisroute</strong>
          <small>${escapeHtml(activeRoute.label)} · ${escapeHtml(activeRoute.meta)}</small>
        </span>
        <em>${routes.length} routes</em>
      </summary>
      <div class="knowledge-task-route-choice__body">
        ${routesMarkup}
      </div>
    </details>
  `;
}

function renderKnowledgeRouteVisibility(
  activeRoute: KnowledgeRoute,
  route: KnowledgeRoute,
): string {
  return route === activeRoute
    ? ' data-knowledge-route-state="active"'
    : ' data-knowledge-route-state="inactive" hidden';
}

function renderEigenKennisItemForm(item?: KennisItem): string {
  const form = `
    <form ${item ? 'class="data-form compact-form knowledge-item-form"' : 'id="knowledge-item-form" class="data-form compact-form knowledge-item-form"'}>
      ${item ? `<input type="hidden" name="kennisId" value="${escapeAttribute(item.id)}" />` : ''}
      <label>
        Titel
        <input name="kennisTitel" value="${escapeAttribute(item?.titel ?? '')}" autocomplete="off" required />
      </label>
      <label>
        Categorie
        <select name="kennisCategorie">
          ${Object.entries(KENNIS_CATEGORIE_LABELS)
            .map(([value, label]) => renderOption(value, label, item?.categorie))
            .join('')}
        </select>
      </label>
      <label>
        Bron of link
        <input name="kennisBron" value="${escapeAttribute(item?.bron ?? '')}" autocomplete="off" />
      </label>
      <label>
        Inhoud
        <textarea name="kennisInhoud" rows="4" required>${escapeHtml(item?.inhoud ?? '')}</textarea>
      </label>
      ${renderFormRequiredMap('knowledge-item', 'Verplicht voor kennisitem', ['Titel', 'Inhoud'])}
      <div class="command-form-actions" data-knowledge-form-actions="knowledge-item">
        <button type="submit">${item ? 'Werk kennisitem bij' : 'Bewaar kennisitem'}</button>
        <a class="form-cancel-link" href="#kennis?route=bibliotheek" data-form-cancel-action="knowledge-item">Annuleer</a>
      </div>
    </form>
  `;

  if (item) return form;

  return `
    <details class="knowledge-add-own-item-choice" data-knowledge-add-own-item-choice="collapsed">
      <summary class="knowledge-add-own-item-choice__summary">
        <span>
          <strong>Itemvelden openen</strong>
          <small>Titel, categorie, broncontext, inhoud en bewaaractie.</small>
        </span>
        <em>Optioneel</em>
      </summary>
      <div class="knowledge-add-own-item-choice__body">
        ${form}
      </div>
    </details>
  `;
}

function renderFormRequiredMap(kind: string, title: string, fields: readonly string[]): string {
  return `
    <section class="form-required-map" data-form-required-map="${escapeAttribute(kind)}" aria-label="${escapeAttribute(title)}">
      <strong>${escapeHtml(title)}</strong>
      <div role="list">
        ${fields.map((field) => `<span role="listitem">${escapeHtml(field)}</span>`).join('')}
      </div>
    </section>
  `;
}

function renderKennisFilterForm(filter: KennisFilter): string {
  const zoekterm = filter.zoekterm?.trim() ?? '';
  const bron = filter.bron?.trim() ?? '';
  const categorieLabel = filter.categorie ? KENNIS_CATEGORIE_LABELS[filter.categorie] : '';
  const verificatieLabel =
    filter.verificatie === 'verified'
      ? 'artsreview'
      : filter.verificatie === 'concept'
        ? 'concept'
        : '';
  const activeFilterCount =
    (zoekterm ? 1 : 0) + (filter.categorie ? 1 : 0) + (bron ? 1 : 0) + (filter.verificatie ? 1 : 0);
  const status =
    activeFilterCount > 0
      ? `${activeFilterCount} actief: ${[
          zoekterm ? `zoekterm "${zoekterm}"` : '',
          categorieLabel ? `categorie ${categorieLabel}` : '',
          bron ? `bron "${bron}"` : '',
          verificatieLabel ? `status ${verificatieLabel}` : '',
        ]
          .filter(Boolean)
          .join(' · ')}`
      : 'Geen filter actief';

  return `
    <form id="knowledge-filter-form" class="data-form compact-form knowledge-filter-kit" data-knowledge-filter-kit="ready" data-knowledge-filter-state="${activeFilterCount > 0 ? 'active' : 'idle'}">
      <details class="knowledge-filter-choice" data-knowledge-filter-choice="collapsed" data-knowledge-filter-form-choice="collapsed">
        <summary class="knowledge-filter-choice__summary">
          <span>
            <strong>Filterformulier openen</strong>
            <small>Open daarna zoekterm, categorie, bron, verificatie en acties.</small>
          </span>
          <em>${escapeHtml(activeFilterCount > 0 ? `${activeFilterCount} actief` : 'Geen filter')}</em>
        </summary>
        <div class="knowledge-filter-choice__body">
          <header class="knowledge-filter-kit__header">
            <div>
              <p class="kp-card__eyebrow">Bibliotheekfilter</p>
              <h3>Kennisitems vinden</h3>
            </div>
            <details class="knowledge-filter-status-choice" data-knowledge-filter-status-choice="collapsed">
              <summary class="knowledge-filter-status-choice__summary">
                <span>
                  <strong>Filterstatus bekijken</strong>
                  <small>Open actieve telling, filterdetails en resetcontext.</small>
                </span>
                <em>${escapeHtml(activeFilterCount > 0 ? `${activeFilterCount} actief` : 'Geen filter')}</em>
              </summary>
              <div class="knowledge-filter-status-choice__body">
                <details class="knowledge-filter-status-detail-choice" data-knowledge-filter-status-detail-choice="collapsed">
                  <summary class="knowledge-filter-status-detail-choice__summary">
                    <span>
                      <strong>Statusdetail openen</strong>
                      <small>Actieve telling, filterdetails en resetcontext.</small>
                    </span>
                    <em>${escapeHtml(activeFilterCount > 0 ? `${activeFilterCount} actief` : 'Geen filter')}</em>
                  </summary>
                  <div class="knowledge-filter-status-detail-choice__body">
                    <span data-knowledge-filter-status-detail="ready">${escapeHtml(status)}</span>
                    <small>Reset staat bij Filtervelden openen.</small>
                  </div>
                </details>
              </div>
            </details>
          </header>
          <details class="knowledge-filter-fields-choice" data-knowledge-filter-fields-choice="collapsed">
            <summary class="knowledge-filter-fields-choice__summary">
              <span>
                <strong>Filtervelden openen</strong>
                <small>Zoekterm, categorie, bron, verificatie en reset.</small>
              </span>
              <em>${escapeHtml(activeFilterCount > 0 ? `${activeFilterCount} actief` : '4 velden')}</em>
            </summary>
            <div class="knowledge-filter-fields-choice__body">
              <div class="knowledge-filter-kit__fields">
                <label class="knowledge-filter-kit__field knowledge-filter-kit__field--search">
                  Zoek
                  <input name="kennisZoekterm" value="${escapeAttribute(filter.zoekterm ?? '')}" autocomplete="off" />
                </label>
                <label class="knowledge-filter-kit__field">
                  Categorie
                  <select name="kennisCategorie">
                    <option value="">Alle categorieën</option>
                    ${Object.entries(KENNIS_CATEGORIE_LABELS)
                      .map(([value, label]) => renderOption(value, label, filter.categorie))
                      .join('')}
                  </select>
                </label>
                <label class="knowledge-filter-kit__field">
                  Bron
                  <input name="kennisBronFilter" value="${escapeAttribute(filter.bron ?? '')}" autocomplete="off" />
                </label>
                <label class="knowledge-filter-kit__field">
                  Verificatie
                  <select name="kennisVerificatie">
                    <option value="">Alle statussen</option>
                    ${renderOption('verified', 'Artsreview', filter.verificatie)}
                    ${renderOption('concept', 'Concept', filter.verificatie)}
                  </select>
                </label>
              </div>
              <div class="knowledge-filter-kit__actions">
                <button type="submit" name="filterAction" value="apply">Filter kennis</button>
                <button class="phase-button secondary" type="submit" name="filterAction" value="clear">Wis filter</button>
              </div>
            </div>
          </details>
        </div>
      </details>
    </form>
  `;
}

function renderKostenScreen(state: AppShellState): string {
  const kosten = state.kosten ?? [];
  const overzicht = berekenKostenOverzicht(kosten);
  const vergoedCount = kosten.filter((item) => item.vergoed === 'ja').length;
  const eigenRisicoCount = kosten.filter((item) => item.vergoed === 'eigen_risico').length;
  const onbekendCount = kosten.filter((item) => item.vergoed === 'onbekend').length;
  const activeFinanceRoute = state.activeFinanceRoute ?? 'overzicht';

  const financeWorkbench = renderFinanceManagementWorkbench({
    costCount: kosten.length,
    vergoedCount,
    eigenRisicoCount,
    onbekendCount,
    overview: overzicht,
    latestCost: kosten[0],
  });
  const financeWorkspace = domainSplitWorkspace({
    className: 'finance-split-workspace',
    ariaLabel: 'Kosten split-view werkruimte',
    data: {
      'finance-split-workspace': 'ready',
      'finance-compact-workspace': 'route-first',
      'finance-single-workspace': 'ready',
    },
    rail: renderFinanceTaskRoutes({
      costCount: kosten.length,
      vergoedCount,
      eigenRisicoCount,
      onbekendCount,
      activeRoute: activeFinanceRoute,
    }),
    context: financeWorkbench,
    main: `
      <section id="kosten-route-overzicht" class="finance-route-section" aria-labelledby="kosten-route-overzicht-title" data-finance-route="overzicht"${renderFinanceRouteVisibility(activeFinanceRoute, 'overzicht')}>
        <header class="finance-route-section__header">
          <p class="kp-card__eyebrow">Overzicht</p>
          <h2 id="kosten-route-overzicht-title">Lokale kostenbibliotheek</h2>
          <p>${FINANCE_CONTEXT_DISCLAIMER}</p>
        </header>
        ${commandRouteSummary({
          eyebrow: 'Kostenroute',
          title: 'Eerst totalen scannen',
          detail:
            'De belangrijkste bedragen blijven direct zichtbaar; detailhistorie en poliscontext staan in eigen routes.',
          primary: { href: '#kosten-route-toevoegen', label: 'Post toevoegen' },
          secondary: { href: '#kosten-route-historie', label: 'Historie' },
          status: `${kosten.length} posten`,
          ariaLabel: 'Kosten overzicht route-samenvatting',
          data: { 'finance-route-summary': 'overzicht' },
        })}
        <dl class="summary-list">
          <div><dt>Totaal</dt><dd>${formatEuro(overzicht.totaal)}</dd></div>
          <div><dt>Vergoed gemarkeerd</dt><dd>${formatEuro(overzicht.vergoed)}</dd></div>
          <div><dt>Mogelijke eigen bijdrage</dt><dd>${formatEuro(overzicht.eigenBijdrage)}</dd></div>
          <div><dt>Nog onbekend</dt><dd>${formatEuro(overzicht.onbekend)}</dd></div>
        </dl>
      </section>
      <section id="kosten-route-toevoegen" class="finance-route-section" aria-labelledby="kosten-route-toevoegen-title" data-finance-route="toevoegen"${renderFinanceRouteVisibility(activeFinanceRoute, 'toevoegen')}>
        <header class="finance-route-section__header">
          <p class="kp-card__eyebrow">Toevoegen</p>
          <h2 id="kosten-route-toevoegen-title">Kostenpost toevoegen</h2>
          <p>Leg facturen of eigen betalingen vast met categorie en vergoedingstatus.</p>
        </header>
        ${commandRouteSummary({
          eyebrow: 'Kostenroute',
          title: 'Nieuwe kostenpost toevoegen zonder historie erboven',
          detail:
            'Het invoerformulier staat vooraan. Overzicht, vergoeding en historie open je pas als vervolgcontext.',
          primary: { href: '#kosten-form', label: 'Formulier' },
          secondary: { href: '#finance-add-followup', label: 'Vervolgcontext' },
          status: `${kosten.length} posten`,
          ariaLabel: 'Kosten toevoegen route-samenvatting',
          data: { 'finance-route-summary': 'toevoegen' },
        })}
        ${renderKostenStatus(state.kostenStatus, 'toevoegen')}
        <div class="finance-add-console" data-finance-add-layout="single-input">
          <div class="summary-panel finance-add-primary" data-finance-add-primary="kosten-form">
            <h3>Kostenpost toevoegen</h3>
            <p class="small-print">${FINANCE_CONTEXT_DISCLAIMER}</p>
            ${renderKostenForm()}
          </div>
          <details id="finance-add-followup" class="kp-disclosure finance-add-followup" data-finance-add-followup="collapsed">
            <summary class="kp-disclosure__summary finance-add-followup__summary">
              <span>
                <strong>Vervolgcontext openen</strong>
                <small>Bekijk totalen, vergoeding of historie pas na de invoer.</small>
              </span>
              <em>${kosten.length} posten</em>
            </summary>
            <div class="kp-disclosure__body finance-add-followup__body">
              <a href="#kosten?route=overzicht">Overzicht bekijken</a>
              <a href="#kosten?route=vergoeding">Vergoeding controleren</a>
              <a href="#kosten?route=historie">Historie openen</a>
            </div>
          </details>
        </div>
      </section>
      <section id="kosten-route-vergoeding" class="finance-route-section" aria-labelledby="kosten-route-vergoeding-title" data-finance-route="vergoeding"${renderFinanceRouteVisibility(activeFinanceRoute, 'vergoeding')}>
        <header class="finance-route-section__header">
          <p class="kp-card__eyebrow">Vergoeding</p>
          <h2 id="kosten-route-vergoeding-title">Vergoeding en eigen risico</h2>
          <p>${FINANCE_CONTEXT_DISCLAIMER}</p>
        </header>
        ${commandRouteSummary({
          eyebrow: 'Kostenroute',
          title: 'Vergoedingscontext apart controleren',
          detail:
            'Eigen risico, onbekende posten en polisdisclaimer openen als controlepaneel, niet als lange startcontent.',
          primary: { href: '#kosten-vergoeding-disclosure', label: 'Context openen' },
          secondary: { href: '#kosten-route-historie', label: 'Onbekend checken' },
          status: `${onbekendCount} onbekend`,
          ariaLabel: 'Kosten vergoeding route-samenvatting',
          data: { 'finance-route-summary': 'vergoeding' },
        })}
        <details id="kosten-vergoeding-disclosure" class="kp-disclosure" data-finance-disclosure="vergoeding">
          <summary class="kp-disclosure__summary">Eigen risico en poliscontext openen</summary>
          <div class="kp-disclosure__body">
            <dl class="summary-list">
              <div><dt>Eigen risico 2026 gebruikt</dt><dd>${formatEuro(overzicht.eigenRisicoGebruikt)}</dd></div>
              <div><dt>Eigen risico 2026 resterend</dt><dd>${formatEuro(overzicht.eigenRisicoResterend)}</dd></div>
              <div><dt>Boven eigen-risicogrens</dt><dd>${formatEuro(overzicht.eigenRisicoBovenGrens)}</dd></div>
              <div><dt>Nog onbekend</dt><dd>${formatEuro(overzicht.onbekend)}</dd></div>
            </dl>
            <p class="small-print">Eigen risico 2026: €385. ${FINANCE_CONTEXT_DISCLAIMER}</p>
          </div>
        </details>
      </section>
      <section id="kosten-route-historie" class="finance-route-section" aria-labelledby="kosten-route-historie-title" data-finance-route="historie"${renderFinanceRouteVisibility(activeFinanceRoute, 'historie')}>
        <header class="finance-route-section__header">
          <p class="kp-card__eyebrow">Historie</p>
          <h2 id="kosten-route-historie-title">Kostenhistorie</h2>
          <p>Bekijk en bewerk eerder vastgelegde kostenposten.</p>
        </header>
        ${commandRouteSummary({
          eyebrow: 'Kostenroute',
          title: 'Historie pas openen om te bewerken',
          detail:
            'Eerdere kostenposten en bewerkformulieren staan achter één openactie zodat het scherm niet als facturenlijst start.',
          primary: { href: '#kosten-historie-disclosure', label: 'Historie openen' },
          secondary: { href: '#kosten-route-toevoegen', label: 'Toevoegen' },
          status: `${kosten.length} posten`,
          ariaLabel: 'Kosten historie route-samenvatting',
          data: { 'finance-route-summary': 'historie' },
        })}
        ${renderKostenStatus(state.kostenStatus, 'historie')}
        <details id="kosten-historie-disclosure" class="kp-disclosure" data-finance-disclosure="historie">
          <summary class="kp-disclosure__summary">Kostenhistorie en bewerken openen</summary>
          <div class="kp-disclosure__body">
            ${
              kosten.length > 0
                ? renderKostenHistoryList(kosten)
                : renderEmptyState('Nog geen kostenposten vastgelegd.', {
                    title: 'Geen kostenposten',
                    cta: { href: '#kosten?route=toevoegen', label: 'Kostenpost toevoegen' },
                  })
            }
          </div>
        </details>
      </section>
        `,
  });

  return sectionStack(
    [
      renderFinanceFocusShell({
        workspace: financeWorkspace,
      }),
    ],
    { className: 'finance-command-layout', ariaLabel: 'Kosten en vergoedingen' },
  );
}

function renderFinanceFocusShell(input: { workspace: string }): string {
  return `
    <section class="finance-focus-shell" aria-labelledby="finance-focus-shell-title" data-finance-focus-shell="ready">
      <header class="finance-focus-shell__header">
        <p class="kp-card__eyebrow">Kostenfocus</p>
        <h2 id="finance-focus-shell-title">Eerst totalen scannen, daarna vergoeding of historie openen</h2>
        <p>Lokale kosten, eigen risico, vergoedingstatus en bewerkhistorie blijven in één administratieruimte zonder financieel advies of polisinterpretatie.</p>
      </header>
      <div class="finance-focus-shell__body" data-finance-console="ready">
        <div class="finance-focus-shell__workspace" data-finance-focus-region="workspace" data-finance-console-region="workspace">
          ${input.workspace}
        </div>
      </div>
    </section>
  `;
}

function renderFinanceManagementWorkbench(input: {
  costCount: number;
  vergoedCount: number;
  eigenRisicoCount: number;
  onbekendCount: number;
  overview: ReturnType<typeof berekenKostenOverzicht>;
  latestCost: CostItem | undefined;
}): string {
  const focus = input.latestCost
    ? `${input.latestCost.omschrijving}: ${formatEuro(input.latestCost.bedrag)}`
    : 'Leg een kostenpost vast om totalen en vergoedingstatus te zien.';
  const status =
    input.onbekendCount > 0
      ? `${input.onbekendCount} onbekend`
      : input.costCount > 0
        ? 'Alles gecategoriseerd'
        : 'Nog geen posten';

  return `
    <section class="management-workbench finance-management-workbench" aria-label="Financiële beheerwerkbank" data-finance-first-viewport="management-workbench">
      <header class="management-workbench__header">
        <div>
          <p class="kp-card__eyebrow">Beheerwerkbank</p>
          <h2>Kosten, vergoeding en eigen risico eerst</h2>
          <p>Scan totalen, vergoedingstatus en eigen-risicocontext zonder financieel advies of polisinterpretatie.</p>
        </div>
        <p class="management-workbench__status">${escapeHtml(status)}</p>
      </header>
      <div class="management-workbench__grid">
        <section class="management-workbench__focus" aria-label="Financiële status">
          <p class="kp-card__eyebrow">Nu eerst</p>
          <h3>${escapeHtml(focus)}</h3>
          <p>${input.costCount} post(en) · ${input.vergoedCount} vergoed · ${input.eigenRisicoCount} eigen risico</p>
        </section>
        <div class="management-workbench__panel">
          ${statRow([
            { label: 'Totaal', value: formatEuro(input.overview.totaal) },
            { label: 'Vergoed', value: formatEuro(input.overview.vergoed) },
            { label: 'Eigen bijdrage', value: formatEuro(input.overview.eigenBijdrage) },
            { label: 'Onbekend', value: formatEuro(input.overview.onbekend) },
          ])}
          <nav class="management-workbench__actions" aria-label="Kosten werkbank acties">
            <a href="#kosten-route-overzicht">Overzicht</a>
            <a href="#kosten-route-vergoeding">Vergoeding</a>
            <a href="#kosten-route-toevoegen">Toevoegen</a>
          </nav>
        </div>
      </div>
    </section>
  `;
}

function renderFinanceTaskRoutes(input: {
  costCount: number;
  vergoedCount: number;
  eigenRisicoCount: number;
  onbekendCount: number;
  activeRoute: FinanceRoute;
}): string {
  const routes: readonly CommandTaskRoute<FinanceRoute>[] = [
    {
      id: 'overzicht',
      href: '#kosten?route=overzicht',
      label: 'Overzicht',
      meta: `${input.costCount} posten`,
      badge: String(input.costCount),
      density: input.costCount > 0 ? 'filled' : 'empty',
    },
    {
      id: 'toevoegen',
      href: '#kosten?route=toevoegen',
      label: 'Toevoegen',
      meta: 'nieuwe post',
      badge: 'nieuw',
      density: 'action',
    },
    {
      id: 'vergoeding',
      href: '#kosten?route=vergoeding',
      label: 'Vergoeding',
      meta: `${input.vergoedCount} vergoed · ${input.eigenRisicoCount} ER`,
      badge: String(input.vergoedCount + input.eigenRisicoCount),
      density: input.vergoedCount + input.eigenRisicoCount > 0 ? 'filled' : 'empty',
    },
    {
      id: 'historie',
      href: '#kosten?route=historie',
      label: 'Historie',
      meta: `${input.onbekendCount} onbekend`,
      badge: String(input.onbekendCount),
      density: input.onbekendCount > 0 ? 'action' : 'empty',
    },
  ];

  return renderCommandTaskRoutes({
    className: 'finance-task-routes',
    routeClassName: 'finance-task-route',
    ariaLabel: 'Kosten taakroutes',
    dataAttribute: 'finance-task-routes',
    routes,
    activeRoute: input.activeRoute,
  });
}

function renderFinanceRouteVisibility(activeRoute: FinanceRoute, route: FinanceRoute): string {
  return route === activeRoute
    ? ' data-finance-route-state="active"'
    : ' data-finance-route-state="inactive" hidden';
}

function renderKostenStatus(status: string | undefined, surface: 'toevoegen' | 'historie'): string {
  if (!status) return '';

  return statusMessage(status, {
    className: 'finance-save-feedback save-feedback',
    data: { 'finance-save-feedback': surface },
    live: 'polite',
    saveFeedback: `finance-${surface}`,
  });
}

function renderKostenForm(selected?: CostItem): string {
  return `
    <form ${selected ? 'class="data-form compact-form kosten-form"' : 'id="kosten-form" class="data-form kosten-form"'}>
      ${selected ? `<input type="hidden" name="id" value="${escapeAttribute(selected.id)}" />` : ''}
      <fieldset class="finance-form-section finance-form-section--primary" data-finance-form-section="kostenpost">
        <legend>Kostenpost</legend>
        <label class="finance-form-field finance-form-field--wide">
          Omschrijving
          <input name="omschrijving" value="${escapeAttribute(selected?.omschrijving ?? '')}" autocomplete="off" required />
        </label>
        <label class="finance-form-field">
          Datum
          <input name="datum" type="date" value="${escapeAttribute(selected?.datum ?? '')}" required />
          <span class="date-format-hint" data-date-format-hint="finance">Gebruik dd-mm-jjjj</span>
        </label>
        <label class="finance-form-field finance-amount-field">
          Bedrag
          <span class="finance-amount-input" data-finance-amount-input="ready">
            <span aria-hidden="true">€</span>
            <input name="bedrag" type="number" min="0" step="0.01" value="${selected?.bedrag ?? ''}" required />
          </span>
        </label>
      </fieldset>
      <fieldset class="finance-form-section" data-finance-form-section="vergoeding-context">
        <legend>Vergoeding en context</legend>
        <label class="finance-form-field">
          Categorie
          <select name="categorie">
            ${Object.entries(COST_CATEGORIE_LABELS)
              .map(([value, label]) => renderOption(value, label, selected?.categorie))
              .join('')}
          </select>
        </label>
        <label class="finance-form-field">
          Vergoeding
          <select name="vergoed">
            ${Object.entries(COST_VERGOED_LABELS)
              .map(([value, label]) => renderOption(value, label, selected?.vergoed))
              .join('')}
          </select>
        </label>
        <label class="finance-form-field finance-form-field--wide">
          Traject-id (optioneel)
          <input name="trajectId" value="${escapeAttribute(selected?.trajectId ?? '')}" autocomplete="off" />
        </label>
      </fieldset>
      ${renderFormRequiredMap('finance-cost', 'Verplicht voor kostenpost', ['Omschrijving', 'Datum', 'Bedrag'])}
      <div class="finance-form-actions">
        <button type="submit">${selected ? 'Werk kostenpost bij' : 'Bewaar kostenpost'}</button>
        ${
          selected
            ? '<a class="form-cancel-link" href="#kosten?route=historie" data-form-cancel-action="finance">Annuleer</a>'
            : ''
        }
        ${
          selected
            ? `<button class="danger-button delete-kosten" type="button" data-kosten-id="${escapeAttribute(selected.id)}" aria-label="Verwijder kostenpost: ${escapeAttribute(selected.omschrijving)}">Verwijder kostenpost</button>`
            : ''
        }
      </div>
    </form>
  `;
}

function renderKostenHistoryList(items: readonly CostItem[]): string {
  return `
    <ol class="cost-history-list" aria-label="Kostenhistorie" data-cost-history-list="ready">
      ${items.map(renderKostenItem).join('')}
    </ol>
  `;
}

function renderKostenItem(item: CostItem): string {
  return `
    <li class="cost-history-card" data-cost-history-card="ready" data-cost-status="${escapeAttribute(item.vergoed)}">
      <article>
        <header class="cost-history-card__header">
          <div class="cost-history-card__title">
            <p class="kp-card__eyebrow">${escapeHtml(COST_CATEGORIE_LABELS[item.categorie])}</p>
            <h3>${escapeHtml(item.omschrijving)}</h3>
          </div>
          ${renderCostAmountCell(item.bedrag)}
        </header>
        <div class="cost-history-card__meta">
          ${renderCostStatusBadge(item.vergoed)}
          <span>${escapeHtml(item.datum)}</span>
          ${item.trajectId ? `<span>Traject: ${escapeHtml(item.trajectId)}</span>` : '<span>Geen traject gekoppeld</span>'}
        </div>
        <details class="cost-history-card__edit">
          <summary>Bewerk kostenpost</summary>
        ${renderKostenForm(item)}
      </details>
      </article>
    </li>
  `;
}

function renderCostStatusBadge(status: CostItem['vergoed']): string {
  return statusBadge({
    label: COST_VERGOED_LABELS[status],
    tone: costStatusBadgeTone(status),
    className: 'status-badge--cost',
    data: {
      'status-badge': 'cost',
      'status-badge-state': status,
    },
  });
}

function renderCostAmountCell(value: number): string {
  const formatted = formatEuro(value);
  const amount = new Intl.NumberFormat('nl-NL', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(value);
  return `<span class="cost-amount cost-history-card__amount cost-amount-cell" data-cost-amount="row" data-cost-amount-cell="ready" aria-label="${escapeAttribute(formatted)}"><span class="cost-amount__currency" aria-hidden="true">€</span><span class="cost-amount__value">${escapeHtml(amount)}</span></span>`;
}

function costStatusBadgeTone(
  status: CostItem['vergoed'],
): 'success' | 'warning' | 'danger' | 'neutral' {
  if (status === 'ja') return 'success';
  if (status === 'eigen_risico') return 'warning';
  if (status === 'nee') return 'danger';
  return 'neutral';
}

function renderResearchItemForm(): string {
  return `
    <details class="knowledge-add-research-input-choice" data-knowledge-add-research-input-choice="collapsed">
      <summary class="knowledge-add-research-input-choice__summary">
        <span>
          <strong>Researchinvoer openen</strong>
          <small>Titel, bron, datum, notitie, samenvattingen en bewaaractie.</small>
        </span>
        <em>Concept</em>
      </summary>
      <div class="knowledge-add-research-input-choice__body">
        <form id="research-item-form" class="data-form compact-form">
          <label>
            Titel
            <input name="researchTitel" autocomplete="off" required />
          </label>
          <label>
            Bron of link
            <input name="researchBron" type="url" autocomplete="off" placeholder="https://..." />
          </label>
          <label>
            Publicatiedatum
            <input name="researchPublicatieDatum" type="date" />
            <span class="date-format-hint" data-date-format-hint="knowledge-research">Gebruik dd-mm-jjjj</span>
          </label>
          <label>
            Notitie
            <textarea name="researchNotitie" rows="4" required></textarea>
          </label>
          <label>
            Wetenschappelijke samenvatting
            <textarea name="researchWetenschappelijkeSamenvatting" rows="4" placeholder="Vat doel, methode, bevindingen en beperkingen samen"></textarea>
          </label>
          <label>
            Eenvoudige samenvatting
            <textarea name="researchEenvoudigeSamenvatting" rows="4" placeholder="Leg in gewone taal uit wat bekend en onzeker is"></textarea>
          </label>
          <p class="small-print">Kiempad bewaart hierbij automatisch scientificSummary, patientSummary en sourceCitation als brongekoppeld concept.</p>
          <label>
            Relevantie voor jullie dossiercontext
            <textarea name="researchRelevantieVoorGebruiker" rows="4" placeholder="Waarom is dit bespreekcontext voor jullie dossier?"></textarea>
          </label>
          ${renderFormRequiredMap('knowledge-research', 'Verplicht voor research', ['Titel', 'Notitie'])}
          <div class="command-form-actions" data-knowledge-form-actions="research">
            <button type="submit">Bewaar research</button>
            <a class="form-cancel-link" href="#kennis?route=bibliotheek" data-form-cancel-action="knowledge-research">Annuleer</a>
          </div>
        </form>
      </div>
    </details>
  `;
}

function renderResearchBronnenCache(bronnen: readonly ResearchBron[]): string {
  return researchSourceList({
    title: 'Researchbronnen',
    intro:
      'Handmatige seed en lokale cache uit opgeslagen researchitems. Kiempad haalt geen publicaties op zonder expliciete netwerk-opt-in.',
    ariaLabel: 'Researchbronnen met allowliststatus',
    data: {
      'research-source-component': 'source-list',
      'research-source-count': String(bronnen.length),
    },
    items: bronnen.map((bron) =>
      researchSourceCard({
        id: bron.id,
        source: bron.bron,
        title: bron.titel,
        meta: `${bron.herkomst === 'handmatige_seed' ? 'Seedbron' : 'Lokale cache'} · ${bron.bron}`,
        detail: `${bron.toelichting} · ${renderResearchBronAllowlistStatus(bron.allowlistStatus)}: ${bron.allowlistRationale}`,
        data: {
          'research-source-origin': bron.herkomst,
          'research-source-allowlist': bron.allowlistStatus,
        },
      }),
    ),
  });
}

function renderWetenschappelijkeResearchSamenvattingen(
  samenvattingen: readonly WetenschappelijkeResearchSamenvatting[],
  kennisItems: readonly KennisItem[],
): string {
  const kennisItemMap = new Map(kennisItems.map((item) => [item.id, item]));
  return researchSummaryList({
    title: 'Wetenschappelijke samenvattingen',
    intro: RESEARCH_CONTEXT_DISCLAIMER,
    kind: 'scientific',
    emptyState: 'Nog geen wetenschappelijke samenvattingen per publicatie vastgelegd.',
    ariaLabel: 'Wetenschappelijke researchsamenvattingen',
    data: {
      'research-summary-component': 'scientific-list',
      'research-summary-count': String(samenvattingen.length),
    },
    items: samenvattingen.map((item) => {
      const kennisItem = kennisItemMap.get(item.id);
      const metadata = kennisItem ? bouwResearchKaartMetadata(kennisItem) : undefined;
      const herverificatie = kennisItem ? bouwResearchHerverificatieStatus(kennisItem) : undefined;
      return researchSummaryCard({
        id: item.id,
        source: item.bron,
        kind: 'scientific',
        title: item.titel,
        meta: `${item.publicatieDatum} · ${item.bron}`,
        summary: item.wetenschappelijkeSamenvatting,
        sourceCitation: item.sourceCitation,
        conceptLabel: item.aiConcept
          ? 'AI-concept · brongekoppeld'
          : 'Handmatig concept · brongekoppeld',
        data: {
          'research-summary-review':
            herverificatie?.status ?? (item.aiConcept ? 'ai-concept' : 'manual-concept'),
        },
        body: `
          <small>sourceCitation: ${escapeHtml(item.sourceCitation)}</small>
          <small>scientificSummary: ${escapeHtml(item.scientificSummary)}</small>
          ${metadata ? renderResearchKaartMetadata(metadata) : ''}
          ${herverificatie ? renderResearchHerverificatieStatus(herverificatie) : ''}
          <small>${escapeHtml(item.waarschuwing)}</small>
        `,
      });
    }),
  });
}

function renderEenvoudigeResearchSamenvattingen(
  samenvattingen: readonly EenvoudigeResearchSamenvatting[],
  kennisItems: readonly KennisItem[],
): string {
  const kennisItemMap = new Map(kennisItems.map((item) => [item.id, item]));
  return researchSummaryList({
    title: 'Eenvoudige samenvattingen',
    intro: RESEARCH_CONTEXT_DISCLAIMER,
    kind: 'patient',
    emptyState: 'Nog geen eenvoudige samenvattingen per publicatie vastgelegd.',
    ariaLabel: 'Eenvoudige researchsamenvattingen',
    data: {
      'research-summary-component': 'patient-list',
      'research-summary-count': String(samenvattingen.length),
    },
    items: samenvattingen.map((item) => {
      const kennisItem = kennisItemMap.get(item.id);
      const metadata = kennisItem ? bouwResearchKaartMetadata(kennisItem) : undefined;
      const herverificatie = kennisItem ? bouwResearchHerverificatieStatus(kennisItem) : undefined;
      return researchSummaryCard({
        id: item.id,
        source: item.bron,
        kind: 'patient',
        title: item.titel,
        meta: `${item.publicatieDatum} · ${item.bron}`,
        summary: item.eenvoudigeSamenvatting,
        sourceCitation: item.sourceCitation,
        conceptLabel: item.aiConcept
          ? 'AI-concept · brongekoppeld'
          : 'Handmatig concept · brongekoppeld',
        data: {
          'research-summary-review':
            herverificatie?.status ?? (item.aiConcept ? 'ai-concept' : 'manual-concept'),
        },
        body: `
          <small>sourceCitation: ${escapeHtml(item.sourceCitation)}</small>
          <small>patientSummary: ${escapeHtml(item.patientSummary)}</small>
          ${metadata ? renderResearchKaartMetadata(metadata) : ''}
          ${herverificatie ? renderResearchHerverificatieStatus(herverificatie) : ''}
          <small>${escapeHtml(item.waarschuwing)}</small>
        `,
      });
    }),
  });
}

function renderResearchRelevantieVoorGebruiker(
  items: readonly ResearchRelevantieVoorGebruiker[],
): string {
  return `
    <section data-research-relevance-panel="ready">
      <h2>Relevantie voor jullie context</h2>
      <p class="small-print">Handmatige contextnotities gekoppeld aan lokale dossierbronnen. Dit is alleen bespreekcontext voor de kliniek.</p>
      ${
        items.length > 0
          ? `<ol class="compact-list">${items
              .map(
                (item) => `
                  <li>
                    <strong>${escapeHtml(item.titel)}</strong>
                    <span>${escapeHtml(item.publicatieDatum)} · ${escapeHtml(item.bron)}</span>
                    <small>${escapeHtml(item.relevantieVoorGebruiker)}</small>
                    <small>Contextmatch: ${escapeHtml(item.contextMatch.label)}</small>
                    <small>Gekoppelde contextfactoren: ${escapeHtml(item.contextMatch.gekoppeldeContextfactoren.join(' · ') || 'nog geen lokale contextfactoren')}</small>
                    <small>Ontbrekende gegevens: ${escapeHtml(item.contextMatch.ontbrekendeGegevens.join(' · ') || 'geen ontbrekende context')}</small>
                    <small>${escapeHtml(item.contextMatch.artsBespreekTaal)}</small>
                    <small>${escapeHtml(item.contextMatch.uitleg)}</small>
                    <dl class="metadata-list compact-list">
                      <div><dt>Relevantiebron</dt><dd>${escapeHtml(item.relevantieUitleg.bron)}</dd></div>
                      <div><dt>Datum</dt><dd>${escapeHtml(item.relevantieUitleg.datum)}</dd></div>
                      <div><dt>Reviewstatus</dt><dd>${escapeHtml(item.relevantieUitleg.reviewStatus)}</dd></div>
                      <div><dt>Onzekerheidslabel</dt><dd>${escapeHtml(item.relevantieUitleg.onzekerheidslabel)}</dd></div>
                      <div><dt>Uitleg voor leken</dt><dd>${escapeHtml(item.relevantieUitleg.uitlegVoorLeken)}</dd></div>
                    </dl>
                    <form class="research-relevance-review-form compact-form" data-research-relevance-id="${escapeAttribute(item.id)}">
                      <input type="hidden" name="researchRelevanceId" value="${escapeAttribute(item.id)}" />
                      <label>
                        Relevantieconcept controleren
                        <input name="researchRelevanceCorrection" value="${escapeAttribute(item.relevantieVoorGebruiker)}" />
                      </label>
                      <label>
                        Reviewstatus
                        <select name="researchRelevanceReviewStatus">
                          ${renderOption('concept_te_controleren', 'Concept te controleren', item.relevantieUitleg.reviewStatus)}
                        </select>
                      </label>
                      <div class="command-form-actions" data-knowledge-form-actions="research-relevance">
                        <button type="submit">Bewaar relevantiecorrectie</button>
                        <a class="form-cancel-link" href="#kennis?route=research" data-form-cancel-action="knowledge-relevance">Annuleer</a>
                      </div>
                    </form>
                    <small>Bronpad: ${item.relevantieUitleg.bronpad.map(escapeHtml).join(' > ')}</small>
                    <small>Correctievelden: ${item.relevantieUitleg.correctieVelden.map(escapeHtml).join(' · ')}</small>
                    <small>${escapeHtml(item.relevantieUitleg.waarschuwing)}</small>
                    ${
                      item.dossierContextBronnen.length > 0
                        ? `<small>Context: ${item.dossierContextBronnen.map((bron) => escapeHtml(bron.label)).join(' · ')}</small>`
                        : '<small>Context: nog geen lokale dossierbron beschikbaar.</small>'
                    }
                    <small>${escapeHtml(item.waarschuwing)}</small>
                  </li>
                `,
              )
              .join('')}</ol>`
          : renderEmptyState('Nog geen relevantie per publicatie aan dossiercontext gekoppeld.', {
              title: 'Geen relevantiekoppeling',
            })
      }
    </section>
  `;
}

function renderResearchDossierRelaties(relaties: readonly ResearchDossierRelatie[]): string {
  return `
    <h2>Research-dossierrelaties</h2>
    <p class="small-print">Herleidbare contextrelaties tussen opgeslagen research en lokale dossierbronnen. Dit is geen causaliteit, diagnose, dosering of behandelkeuze.</p>
    ${
      relaties.length > 0
        ? `<ol class="compact-list">${relaties
            .map(
              (relatie) => `
                <li>
                  <strong>${escapeHtml(relatie.researchTitel)}</strong>
                  <span>${escapeHtml(relatie.publicatieDatum)} · ${escapeHtml(relatie.dossierContextBron.label)}</span>
                  <small>${escapeHtml(relatie.relatieLabel)}</small>
                  <small>Bronpad: ${relatie.bronpad.map((stap) => escapeHtml(stap)).join(' > ')}</small>
                  <small>Onzekerheid: contextrelatie, geen causaliteit.</small>
                  <small>${escapeHtml(relatie.waarschuwing)}</small>
                </li>
              `,
            )
            .join('')}</ol>`
        : renderEmptyState('Nog geen research-dossierrelaties beschikbaar.', {
            title: 'Geen researchrelaties',
          })
    }
  `;
}

function renderResearchTrendGroepen(groepen: readonly ResearchTrendGroep[]): string {
  const itemCount = groepen.reduce((total, groep) => total + groep.items.length, 0);
  return `
    <section class="research-trend-dashboard" aria-label="Research trenddashboard" data-research-trend-dashboard="ready" data-research-trend-state="${groepen.length > 0 ? 'filled' : 'empty'}">
      <header class="research-trend-dashboard__header">
        <div>
          <p class="kp-card__eyebrow">Trenddashboard</p>
          <h2>Researchtrends</h2>
          <p>${RESEARCH_CONTEXT_DISCLAIMER}</p>
        </div>
        <dl class="research-trend-dashboard__stats" aria-label="Researchtrend status">
          <div><dt>Groepen</dt><dd>${groepen.length}</dd></div>
          <div><dt>Items</dt><dd>${itemCount}</dd></div>
        </dl>
      </header>
      ${
        groepen.length > 0
          ? `<div class="research-trend-dashboard__grid" data-research-trend-grid="ready">${groepen
              .map(renderResearchTrendCard)
              .join('')}</div>`
          : renderEmptyState('Nog geen researchtrends gevonden in opgeslagen researchitems.', {
              title: 'Geen researchtrends',
            })
      }
    </section>
  `;
}

function renderResearchTrendCard(groep: ResearchTrendGroep): string {
  return `
    <article class="research-trend-card" data-research-trend-card="${escapeAttribute(groep.onderwerp)}">
      <header class="research-trend-card__header">
        <span class="research-trend-card__topic">${escapeHtml(groep.label)}</span>
        <strong>${groep.items.length} item${groep.items.length === 1 ? '' : 's'}</strong>
      </header>
      <p class="research-trend-card__warning">${escapeHtml(groep.waarschuwing)}</p>
      <ol class="research-trend-card__items">
        ${groep.items.map(renderResearchTrendCardItem).join('')}
      </ol>
    </article>
  `;
}

function renderResearchTrendCardItem(item: ResearchTrendGroep['items'][number]): string {
  const metadata = [item.publicatieDatum, item.bron].filter((value): value is string =>
    Boolean(value),
  );
  return `
    <li class="research-trend-card__item" data-research-trend-item="${escapeAttribute(item.id)}">
      <span>${escapeHtml(item.titel)}</span>
      <small>${metadata.map((value) => escapeHtml(value)).join(' · ') || 'Bronmetadata ontbreekt'}</small>
    </li>
  `;
}

function renderResearchNetworkSettingsForm(settings: AppSettings): string {
  return `
    <h2>Researchaggregatie</h2>
    <form id="research-network-form" class="data-form compact-form">
      <label>
        Netwerkresearch
        <select name="researchNetwerkIngeschakeld">
          ${renderOption('false', 'Uit: alleen lokale cache', String(settings.researchNetwerk.ingeschakeld))}
          ${renderOption('true', 'Aan na expliciete opt-in', String(settings.researchNetwerk.ingeschakeld))}
        </select>
      </label>
      <div class="command-form-actions" data-knowledge-form-actions="research-network">
        <button type="submit">Bewaar research-opt-in</button>
        <a class="form-cancel-link" href="#kennis?route=research" data-form-cancel-action="knowledge-research-network">Annuleer</a>
      </div>
    </form>
    <p class="small-print">Deze instelling bewaart alleen toestemming. Kiempad start geen automatische netwerkrequest.</p>
  `;
}

function renderResearchAggregatiePlan(plan: ResearchAggregatiePlan): string {
  return `
    <div class="policy-panel embedded-summary" aria-label="Researchaggregatie-status">
      <h3>Aggregatiestatus</h3>
      <p class="small-print">${escapeHtml(plan.waarschuwing)}</p>
      <p>${plan.status === 'klaar_voor_handmatige_start' ? `${plan.bronnen.length} bron(nen) klaar voor handmatige aggregatie.` : 'Aggregatie uitgeschakeld.'}</p>
      ${renderPubMedQueryPreview(plan.pubMedQueryPreview)}
      <h4>Research bronregister</h4>
      <p class="small-print">Bronnen met naam, type, URL, updatebeleid en opt-invereiste. Dit register start geen netwerkcalls.</p>
      <ol class="compact-list" aria-label="Research bronregister">
        ${plan.bronregister
          .map(
            (bron) => `
              <li>
                <strong>${escapeHtml(bron.naam)}</strong>
                <span>${escapeHtml(bron.type)} · ${escapeHtml(bron.url)}</span>
                <small>Updatebeleid: ${escapeHtml(bron.updatebeleid)} · ${escapeHtml(bron.optInVereist ? 'Opt-in vereist' : 'Geen netwerk-opt-in vereist')}</small>
                <small>${escapeHtml(bron.bronmetadata.netwerkGedrag)} · ${escapeHtml(bron.bronmetadata.allowlistStatus)}</small>
              </li>
            `,
          )
          .join('')}
      </ol>
      ${
        plan.bronnen.length > 0
          ? `<ol class="compact-list">${plan.bronnen
              .map(
                (bron) =>
                  `<li>${escapeHtml(bron.titel)} · ${escapeHtml(bron.bron)} · ${escapeHtml(bron.herkomst === 'handmatige_seed' ? 'Seedbron' : 'Lokale cache')}</li>`,
              )
              .join('')}</ol>`
          : ''
      }
    </div>
  `;
}

function renderPubMedQueryPreview(preview: PubMedQueryPreview): string {
  return `
    <section class="policy-panel embedded-summary" aria-label="PubMed query preview zonder dossierplaintext">
      <h4>PubMed query preview</h4>
      <p class="small-print">${escapeHtml(preview.waarschuwing)}</p>
      <dl class="metadata-list compact-list">
        <div><dt>Bron</dt><dd>${escapeHtml(preview.bron)} · ${escapeHtml(preview.bronUrl)}</dd></div>
        <div><dt>Datum</dt><dd>${escapeHtml(preview.datum)}</dd></div>
        <div><dt>Reviewstatus</dt><dd>${escapeHtml(preview.reviewStatus)}</dd></div>
        <div><dt>Query</dt><dd>${escapeHtml(preview.query)}</dd></div>
        <div><dt>Previewlink</dt><dd>${escapeHtml(preview.previewUrl)}</dd></div>
      </dl>
      <form id="pubmed-query-preview-form" class="data-form compact-form">
        <input type="hidden" name="pubmedPreviewId" value="${escapeAttribute(preview.id)}" />
        <label>
          Zoektermen controleren
          <input name="pubmedZoektermen" value="${escapeAttribute(preview.zoektermen.join(', '))}" />
        </label>
        <label>
          Datum
          <input name="pubmedPreviewDatum" type="date" value="${escapeAttribute(preview.datum)}" />
          <span class="date-format-hint" data-date-format-hint="knowledge-pubmed">Gebruik dd-mm-jjjj</span>
        </label>
        <label>
          Reviewstatus
          <select name="pubmedReviewStatus">
            ${renderOption('concept_te_controleren', 'Concept te controleren', preview.reviewStatus)}
          </select>
        </label>
        <div class="command-form-actions" data-knowledge-form-actions="pubmed-preview">
          <button type="submit">Bewaar PubMed-previewcorrectie</button>
          <a class="form-cancel-link" href="#kennis?route=research" data-form-cancel-action="knowledge-pubmed">Annuleer</a>
        </div>
      </form>
      <p class="small-print">Uitgesloten context: ${preview.uitgeslotenContext.map(escapeHtml).join(' · ')}</p>
      <p class="small-print">Correctievelden: ${preview.correctieVelden.map(escapeHtml).join(' · ')}</p>
    </section>
  `;
}

function renderAiPreviewForm(preview?: AiSamenvattingPayload, error?: string): string {
  return `
    <details class="knowledge-ai-preview-content-choice" data-knowledge-ai-preview-content-choice="collapsed">
      <summary class="knowledge-ai-preview-content-choice__summary">
        <span>
          <strong>Previewinhoud openen</strong>
          <small>Bron, previewtekst, foutstatus en previewactie.</small>
        </span>
        <em>${error ? 'Controle nodig' : preview ? 'Preview klaar' : 'Geen preview'}</em>
      </summary>
      <div class="knowledge-ai-preview-content-choice__body">
        <form id="ai-preview-form" class="data-form compact-form" data-ai-preview-state="${preview ? 'preview' : 'leeg'}" data-ai-preview-feedback-state="${error ? 'error' : preview ? 'preview' : 'idle'}">
          <label>
            Bron
            <input name="aiBron" value="${escapeAttribute(preview?.bron ?? '')}" autocomplete="off" required />
          </label>
          <label>
            Tekst voor preview
            <textarea name="aiBronTekst" rows="5" required>${escapeHtml(preview?.tekst ?? '')}</textarea>
          </label>
          ${renderFormRequiredMap('knowledge-ai-preview', 'Verplicht voor payload-preview', ['Bron', 'Tekst voor preview'])}
          <div class="command-form-actions" data-knowledge-form-actions="ai-preview">
            <button type="submit">Toon payload-preview</button>
            <a class="form-cancel-link" href="#kennis?route=ai" data-form-cancel-action="knowledge-ai-preview">Annuleer</a>
          </div>
        </form>
        ${
          preview
            ? `<div class="policy-panel embedded-summary" aria-label="AI payload-preview">
                <h3>Payload-preview</h3>
                <p class="small-print">${preview.lengteVerstuurd} van ${preview.lengteOrigineel} tekens na minimalisatie.</p>
                ${renderAiRedactionPreview(preview)}
                <pre class="payload-preview">${escapeHtml(preview.tekst)}</pre>
              </div>`
            : ''
        }
        ${error ? `<p class="form-error" role="alert">${escapeHtml(sanitizeSettingsPrivacyFeedback(error, 'AI-previewstatus bijgewerkt zonder provider- of broninhoud.'))}</p>` : ''}
      </div>
    </details>
  `;
}

function renderAiRedactionPreview(preview: AiSamenvattingPayload): string {
  if (preview.redacties.length === 0) {
    return '<p class="small-print">Geen persoonlijke identifiers herkend in deze preview.</p>';
  }

  return `
    <section class="linked-note" aria-label="Verwijderde persoonlijke velden">
      <h4>Verwijderde velden</h4>
      <ul class="compact-list">
        ${preview.redacties
          .map(
            (redactie) =>
              `<li>${escapeHtml(redactie.label)}: ${redactie.aantal}x vervangen door ${escapeHtml(redactie.vervanging)}</li>`,
          )
          .join('')}
      </ul>
    </section>
  `;
}

function renderAiSummaryForm(preview?: AiSamenvattingPayload): string {
  return `
    <details class="knowledge-ai-summary-save-choice" data-knowledge-ai-summary-save-choice="collapsed">
      <summary class="knowledge-ai-summary-save-choice__summary">
        <span>
          <strong>Opslagvelden openen</strong>
          <small>Samenvatting, broncontext, status en opslagactie.</small>
        </span>
        <em>${preview ? 'Preview klaar' : 'Geen preview'}</em>
      </summary>
      <div class="knowledge-ai-summary-save-choice__body">
        <form id="ai-summary-form" class="data-form compact-form">
          <label>
            Titel
            <input name="aiTitel" value="${escapeAttribute(preview ? 'AI-samenvatting research' : '')}" required />
          </label>
          <label>
            Bron
            <input name="aiSamenvattingBron" value="${escapeAttribute(preview?.bron ?? '')}" autocomplete="off" required />
          </label>
          <label>
            Samenvatting
            <textarea name="aiSamenvatting" rows="5" required></textarea>
          </label>
          ${renderFormRequiredMap('knowledge-ai-summary', 'Verplicht voor AI-samenvatting', ['Titel', 'Bron', 'Samenvatting'])}
          <div class="command-form-actions" data-knowledge-form-actions="ai-summary">
            <button type="submit">Bewaar als kennisitem</button>
            <a class="form-cancel-link" href="#kennis?route=ai" data-form-cancel-action="knowledge-ai-summary">Annuleer</a>
          </div>
        </form>
      </div>
    </details>
  `;
}

function renderAiSettingsForm(
  settings: AppSettings,
  storageMode: AppShellState['storageMode'],
): string {
  const central = storageMode === 'central-api';
  const storageCopy = central
    ? 'Provider, model en toegangssleutel worden op je toestel versleuteld voordat ze centraal worden bewaard; de server ziet de sleutel niet leesbaar.'
    : 'Provider, model en toegangssleutel blijven versleuteld in de lokale kluis op dit toestel.';
  const provider = sanitizeSettingsPrivacyFeedback(settings.ai.provider ?? '', '');
  const model = sanitizeSettingsPrivacyFeedback(settings.ai.model ?? '', '');

  return `
    <form id="ai-settings-form" class="data-form compact-form" data-settings-feedback-kind="ai" data-ai-settings-feedback-state="${settings.ai.ingeschakeld ? 'configured' : 'disabled'}" data-ai-state="${settings.ai.ingeschakeld ? 'aan' : 'uit'}" data-ai-storage="${central ? 'central-api' : 'local-legacy'}">
      <label>
        AI
        <select name="aiIngeschakeld">
          ${renderOption('false', 'Uit', String(settings.ai.ingeschakeld))}
          ${renderOption('true', 'Aan na expliciete actie', String(settings.ai.ingeschakeld))}
        </select>
      </label>
      <label>
        Provider
        <input name="aiProvider" value="${escapeAttribute(provider)}" autocomplete="off" />
      </label>
      <label>
        Model
        <input name="aiModel" value="${escapeAttribute(model)}" autocomplete="off" />
      </label>
      <label>
        Toegangssleutel
        <input name="aiApiKey" type="password" value="" placeholder="${settings.ai.apiKey ? 'Opgeslagen; laat leeg om te bewaren' : ''}" autocomplete="off" />
      </label>
      <p class="small-print">${storageCopy}</p>
      <div class="command-form-actions" data-knowledge-form-actions="ai-settings">
        <button type="submit">Bewaar AI-instelling</button>
        <a class="form-cancel-link" href="#kennis?route=ai" data-form-cancel-action="knowledge-ai-settings">Annuleer</a>
      </div>
    </form>
  `;
}

function renderOnDeviceAiStatus(capabilities: OnDeviceAiCapability[]): string {
  const capabilityState = capabilities.some((capability) => capability.beschikbaar)
    ? 'beschikbaar'
    : 'niet-beschikbaar';
  return `
    <div class="policy-panel embedded-summary" aria-label="On-device AI verkenning" data-on-device-ai-state="${capabilityState}">
      <h3>On-device AI</h3>
      <p class="small-print">${escapeHtml(beschrijfOnDeviceAiStatus(capabilities))}</p>
      <p class="small-print">Verkenning zonder cloud-stap: Kiempad start geen AI-sessie, downloadt geen model en verstuurt niets.</p>
      <dl class="summary-list">
        ${capabilities
          .map(
            (capability) => `
              <div>
                <dt>${escapeHtml(capability.label)}</dt>
                <dd>
                  <span class="status-pill">${capability.beschikbaar ? 'API-object aanwezig' : 'Niet aanwezig'}</span>
                  <span>${escapeHtml(capability.globaalObject)} · ${escapeHtml(capability.toelichting)}</span>
                </dd>
              </div>
            `,
          )
          .join('')}
      </dl>
    </div>
  `;
}

function renderKennisCategorie(label: string, items: KennisItem[]): string {
  const categorie = Object.entries(KENNIS_CATEGORIE_LABELS).find(
    ([, categorieLabel]) => categorieLabel === label,
  )?.[0];
  const id = categorie ? ` id="knowledge-category-${escapeAttribute(categorie)}"` : '';

  return `
    <section${id} class="knowledge-category" aria-label="${label}" data-knowledge-category="ready">
      <header class="knowledge-category__header">
        <p class="kp-card__eyebrow">Categorie</p>
        <h2>${label}</h2>
        <span>${items.length} item${items.length === 1 ? '' : 's'}</span>
      </header>
      ${
        items.length > 0
          ? `<details class="knowledge-library-list-choice" data-knowledge-library-list-choice="collapsed">
              <summary class="knowledge-library-list-choice__summary">
                <span>
                  <strong>Bibliotheeklijst openen</strong>
                  <small>Open kennisitems, detailacties en categoriecontext.</small>
                </span>
                <em>${items.length} item${items.length === 1 ? '' : 's'}</em>
              </summary>
              <div class="knowledge-library-list-choice__body">
                <details class="knowledge-library-list-items-choice" data-knowledge-library-list-items-choice="collapsed">
                  <summary class="knowledge-library-list-items-choice__summary">
                    <span>
                      <strong>Lijstitems openen</strong>
                      <small>Itemkaarten, categorie, status en broninformatie.</small>
                    </span>
                    <em>${items.length} item${items.length === 1 ? '' : 's'}</em>
                  </summary>
                  <div class="knowledge-library-list-items-choice__body">
                    <ol class="knowledge-library-list" aria-label="Kennisitems in ${escapeAttribute(label)}" data-knowledge-library-list="ready">${items.map(renderKennisItem).join('')}</ol>
                  </div>
                </details>
              </div>
            </details>`
          : renderEmptyState('Nog geen items in deze categorie.', { title: 'Categorie is leeg' })
      }
    </section>
  `;
}

function renderKennisItem(item: KennisItem): string {
  const kostenJaar = bepaalKennisKostenJaar(item);
  const researchMetadata = bouwResearchKaartMetadata(item);
  const researchHerverificatie = bouwResearchHerverificatieStatus(item);
  const badges = renderKennisStatusBadges(item, kostenJaar);

  return `
    <li class="knowledge-library-card" data-knowledge-library-card="ready" data-knowledge-card-category="${escapeAttribute(item.categorie)}" data-knowledge-card-verification="${item.geverifieerd_met_arts ? 'verified' : 'concept'}">
      <article>
        <header class="knowledge-library-card__header">
          <div>
            <p class="kp-card__eyebrow">${escapeHtml(KENNIS_CATEGORIE_LABELS[item.categorie])}</p>
            <h3>${escapeHtml(item.titel)}</h3>
          </div>
          <span class="knowledge-library-card__chevron" aria-hidden="true">&rsaquo;</span>
        </header>
        <details class="knowledge-library-card-detail-choice" data-knowledge-library-card-detail-choice="collapsed">
          <summary class="knowledge-library-card-detail-choice__summary">
            <span>
              <strong>Kaartdetails openen</strong>
              <small>Open inhoud, bron, badges en acties.</small>
            </span>
            <em>${item.geverifieerd_met_arts ? 'Artscheck' : 'Concept'}</em>
          </summary>
          <div class="knowledge-library-card-detail-choice__body">
            <details class="knowledge-library-card-content-choice" data-knowledge-library-card-content-choice="collapsed">
              <summary class="knowledge-library-card-content-choice__summary">
                <span>
                  <strong>Kaartinhoud openen</strong>
                  <small>Inhoud, bron, badges en acties.</small>
                </span>
                <em>${item.geverifieerd_met_arts ? 'Artscheck' : 'Concept'}</em>
              </summary>
              <div class="knowledge-library-card-content-choice__body">
                <p class="knowledge-library-card__body">${escapeHtml(item.inhoud)}</p>
                <p class="knowledge-library-card__source">Bron: ${escapeHtml(item.bron ?? 'Geen bron vastgelegd')}</p>
                ${researchMetadata ? renderResearchKaartMetadata(researchMetadata) : ''}
                ${researchHerverificatie ? renderResearchHerverificatieStatus(researchHerverificatie) : ''}
                ${
                  item.geverifieerdOp
                    ? `<p class="linked-note">Geverifieerd op ${escapeHtml(item.geverifieerdOp)} · review uiterlijk ${escapeHtml(item.volgendeVerificatieOp ?? 'onbekend')}</p>`
                    : '<p class="linked-note">Nog niet met behandelaar geverifieerd.</p>'
                }
                <div class="knowledge-library-card__badges" aria-label="Kennisitem status">
                  ${badges}
                </div>
                <div class="knowledge-library-card__actions">
                  ${
                    item.geverifieerd_met_arts
                      ? '<span class="knowledge-library-card__verified">Artscheck vastgelegd</span>'
                      : `<button class="phase-button" type="button" data-kennis-id="${item.id}" aria-label="Markeer kennisitem als geverifieerd: ${escapeAttribute(item.titel)}">Markeer geverifieerd</button>`
                  }
                  ${
                    isEigenKennisItem(item)
                      ? `<details class="knowledge-library-card__edit">
                          <summary>Bewerk kennisitem</summary>
                          ${renderEigenKennisItemForm(item)}
                        </details>`
                      : ''
                  }
                </div>
              </div>
            </details>
          </div>
        </details>
      </article>
    </li>
  `;
}

function renderKennisStatusBadges(item: KennisItem, kostenJaar: string | undefined): string {
  return [
    statusBadge({
      label: item.ai_gegenereerd ? 'AI-gegenereerd' : 'Handmatig',
      tone: item.ai_gegenereerd ? 'info' : 'neutral',
      className: 'status-badge--knowledge',
      data: {
        'status-badge': 'knowledge',
        'status-badge-state': item.ai_gegenereerd ? 'ai' : 'manual',
      },
    }),
    statusBadge({
      label: item.geverifieerd_met_arts ? 'Artscheck vastgelegd' : 'Concept',
      tone: item.geverifieerd_met_arts ? 'success' : 'warning',
      className: 'status-badge--knowledge',
      data: {
        'status-badge': 'knowledge',
        'status-badge-state': item.geverifieerd_met_arts ? 'verified' : 'concept',
      },
    }),
    ...(kostenJaar
      ? [
          statusBadge({
            label: `Kostenjaar ${kostenJaar}`,
            tone: 'info',
            className: 'status-badge--knowledge',
            data: {
              'status-badge': 'knowledge',
              'status-badge-state': 'cost-year',
            },
          }),
        ]
      : []),
  ].join('');
}

function renderResearchHerverificatieStatus(status: ResearchHerverificatieStatus): string {
  return `
    <p class="linked-note">${escapeHtml(status.label)}${status.volgendeHerverificatieOp ? ` · volgende herverificatie: ${escapeHtml(status.volgendeHerverificatieOp)}` : ''}</p>
    <small>${escapeHtml(status.waarschuwing)}</small>
  `;
}

function renderResearchKaartMetadata(metadata: ResearchKaartMetadata): string {
  return `
    <dl class="summary-list">
      <div><dt>Bronverificatie</dt><dd>${escapeHtml(metadata.bronverificatie)}</dd></div>
      <div><dt>Bronrationale</dt><dd>${escapeHtml(metadata.bronRationale)}</dd></div>
      <div><dt>Publicatiedatum</dt><dd>${escapeHtml(metadata.publicatieDatum)}</dd></div>
      <div><dt>Researchbron</dt><dd>${escapeHtml(metadata.bron)}</dd></div>
    </dl>
  `;
}

function renderResearchBronAllowlistStatus(status: ResearchBron['allowlistStatus']): string {
  if (status === 'toegestaan_met_rationale') return 'Allowlist';
  if (status === 'lokale_notitie') return 'Lokale notitie';
  return 'Handmatige review';
}

function isEigenKennisItem(item: KennisItem): boolean {
  return !item.id.startsWith('seed-') && !item.ai_gegenereerd;
}

function renderStartScreen(state: AppShellState): string {
  const activeTraject = state.trajecten[0];
  const sortedFasen = activeTraject ? sorteerFasen(activeTraject.fasen) : [];
  const huidigeFase = activeTraject ? bepaalHuidigeFase(activeTraject.fasen) : undefined;
  const faseSteps = sortedFasen.map((fase) => ({
    label: TRAJECT_FASE_LABELS[fase.fase],
    state: (fase.eindDatum
      ? 'done'
      : huidigeFase && fase.fase === huidigeFase.fase
        ? 'current'
        : 'todo') as StepState,
  }));
  const huidigeFaseIndex = huidigeFase
    ? sortedFasen.findIndex((fase) => fase.fase === huidigeFase.fase) + 1
    : 0;
  const vandaag = new Date().toISOString().slice(0, 10);
  const nextAppointment = beschrijfVolgendeAfspraak(
    state.afspraken.map((bundle) => bundle.afspraak),
    new Date().toISOString().slice(0, 16),
  );
  const nextReminder = beschrijfVolgendeHerinnering(state.herinneringen);
  const openQuestions = beschrijfOpenstaandeVragen(state);
  const dailyRecommendations = bouwDagelijksAanbevelingsoverzicht({
    datum: vandaag,
    afspraken: state.afspraken.map((bundle) => bundle.afspraak),
    medicatie: state.medicatie,
    vragen: state.vragen.map((bundle) => bundle.vraag),
    consultVerslagen: state.consultVerslagen ?? [],
    trajecten: state.trajecten,
    dossierDocuments: state.dossierDocuments ?? [],
    cycleData: state.cycleData ?? [],
  });
  const todayDoseLogs = doseLogsVoorDag(
    state.medicatie.flatMap((bundle) => bundle.doseLogs),
    vandaag,
  );
  const phasePanel = phaseHeroCard(
    huidigeFase
      ? {
          id: 'start-current-phase',
          eyebrow: `Huidige fase · ${huidigeFaseIndex} van ${sortedFasen.length}`,
          phaseLabel: TRAJECT_FASE_LABELS[huidigeFase.fase],
          subtitle: TRAJECT_FASE_TOELICHTING[huidigeFase.fase],
          steps: faseSteps,
          cta: { href: '#traject', label: 'Bekijk traject' },
        }
      : {
          id: 'start-current-phase',
          eyebrow: activeTraject ? 'Jullie traject' : 'Aan de slag',
          phaseLabel: activeTraject ? activeTraject.traject.naam : 'Begin jullie traject',
          subtitle: activeTraject
            ? bepaalVolgendeStap(activeTraject)
            : 'Maak een traject aan om de eerste fase en volgende stap zichtbaar te maken.',
          steps: faseSteps,
          cta: {
            href: '#traject',
            label: activeTraject ? 'Bekijk traject' : 'Traject aanmaken',
          },
        },
  );
  const setupPanel = renderFirstRunSetup(state);

  const startHeader = renderStartCommandHeader(state);
  const startCockpit = renderStartCockpit({
    activeTraject,
    huidigeFase,
    nextAppointment,
    nextReminder,
    openQuestions,
    doseCount: todayDoseLogs.length,
    recommendationCount: (['vrouw', 'man', 'samen'] as const).reduce(
      (total, owner) => total + dailyRecommendations[owner].length,
      0,
    ),
    dossierCount: state.dossierDocuments?.length ?? 0,
    consultCount: state.consultVerslagen?.length ?? 0,
    researchCount: state.kennisItems.length,
    secureMode: isCentralStorage(state) ? 'Centrale dataset' : 'Lokale kluis',
  });
  const startWorkspaceDeck = renderStartWorkspaceDeck({
    appointmentCount: state.afspraken.length,
    reminderCount: state.herinneringen.length,
    dossierCount: state.dossierDocuments?.length ?? 0,
    consultCount: state.consultVerslagen?.length ?? 0,
    researchCount: state.kennisItems.length,
    recommendationCount: (['vrouw', 'man', 'samen'] as const).reduce(
      (total, owner) => total + dailyRecommendations[owner].length,
      0,
    ),
    costCount: state.kosten?.length ?? 0,
    secureMode: isCentralStorage(state) ? 'Centrale versleutelde opslag' : 'Lokale kluis',
  });
  const primaryDayAction = renderStartPrimaryDayAction({
    activeTraject,
    huidigeFase,
    nextAppointment,
    nextReminder,
    openQuestions,
    doseCount: todayDoseLogs.length,
    recommendationCount: (['vrouw', 'man', 'samen'] as const).reduce(
      (total, owner) => total + dailyRecommendations[owner].length,
      0,
    ),
  });
  const dailyAdviceConsole = renderDailyAdviceConsole(state, dailyRecommendations);
  const startTodayConsole = renderStartTodayConsole({
    phase: phasePanel,
    planning: renderStartNextStepBoard(nextAppointment, nextReminder, openQuestions),
    command: renderDailyCommandCenter(state, vandaag, localDateTimeIso(new Date())),
    quickEntry: renderStartQuickEntryRoute(),
  });

  if (state.activeStartRoute === 'today') {
    return sectionStack([startTodayConsole], {
      className: 'start-today-route-layout',
      ariaLabel: 'Vandaag beheren',
      data: { 'start-today-route': 'ready' },
    });
  }

  if (state.activeStartRoute === 'recommendations') {
    return sectionStack([dailyAdviceConsole], {
      className: 'start-daily-advice-route-layout',
      ariaLabel: 'Dagadvies beheren',
      data: { 'start-daily-advice-route': 'ready' },
    });
  }

  return sectionStack(
    [
      renderStartLaunchpad({
        header: startHeader,
        primaryDayAction,
        cockpit: startCockpit,
        workspaceDeck: startWorkspaceDeck,
        setup: setupPanel,
      }),
    ],
    {
      className: 'start-command-layout',
      ariaLabel: 'Startoverzicht',
      data: { 'start-console': 'ready' },
    },
  );
}

