function filterDailyRecommendationOverview(
  overview: DailyRecommendationOverview,
  feedbackStatussen: Partial<Record<string, FertilityTimelineAanbevelingFeedbackStatus>>,
  filter?: FertilityTimelineAanbevelingFeedbackStatus,
): DailyRecommendationOverview {
  if (!filter) return overview;
  return {
    vrouw: overview.vrouw.filter((item) => feedbackStatussen[item.id] === filter),
    man: overview.man.filter((item) => feedbackStatussen[item.id] === filter),
    samen: overview.samen.filter((item) => feedbackStatussen[item.id] === filter),
  };
}

function renderDailyRecommendationListFilterHeader(input: {
  filter?: FertilityTimelineAanbevelingFeedbackStatus;
  total: number;
  filteredTotal: number;
  overview: DailyRecommendationOverview;
}): string {
  if (!input.filter) return '';
  const filterLabel = FERTILITY_TIMELINE_AANBEVELING_FEEDBACK_LABELS[input.filter];
  const ownerCounts = (['vrouw', 'man', 'samen'] as const).map((owner, index) => ({
    owner,
    count: input.overview[owner].length,
    index,
  }));
  const highestCount = Math.max(...ownerCounts.map((item) => item.count));
  const hasSingleDominantOwner =
    highestCount > 0 && ownerCounts.filter((item) => item.count === highestCount).length === 1;
  const ownerDistribution = ownerCounts
    .sort((left, right) => {
      const leftHasResults = left.count > 0 ? 1 : 0;
      const rightHasResults = right.count > 0 ? 1 : 0;
      return rightHasResults - leftHasResults || left.index - right.index;
    })
    .map(({ owner, count }) => {
      const state = count === 0 ? 'empty' : 'filled';
      const emphasis = hasSingleDominantOwner && count === highestCount ? 'dominant' : 'regular';
      return `<span data-daily-recommendation-list-filter-owner="${owner}" data-daily-recommendation-list-filter-owner-state="${state}" data-daily-recommendation-list-filter-owner-emphasis="${emphasis}" data-daily-recommendation-list-filter-owner-count="${count}">${escapeHtml(DAILY_RECOMMENDATION_OWNER_LABELS[owner])}: ${count}</span>`;
    })
    .join('');

  return `
    <div class="daily-recommendation-list-filter-header" data-daily-recommendation-list-filter-header="ready">
      <span>Actieve lijstfilter</span>
      <strong>${escapeHtml(filterLabel)}</strong>
      <em>${input.filteredTotal} van ${input.total} suggesties</em>
      <span class="daily-recommendation-list-filter-header__owners" data-daily-recommendation-list-filter-owners="ready">${ownerDistribution}</span>
      <span class="daily-recommendation-list-filter-header__legend" data-daily-recommendation-list-filter-legend="ready">
        <span data-daily-recommendation-list-filter-legend-item="accent">Accent = meeste</span>
        <span data-daily-recommendation-list-filter-legend-item="empty">Licht = geen match</span>
      </span>
      <form data-daily-recommendation-feedback-control="ready">
        <button type="submit" name="dailyRecommendationFeedbackFilterAction" value="reset" data-daily-recommendation-list-filter-reset="ready" aria-label="Wis alleen de lokale feedbackfilter">Wis lokale filter</button>
      </form>
    </div>
  `;
}

