function renderFertilityTimelineItem(item: FertilityTimeline['items'][number]): string {
  const reviewState = bepaalFertilityTimelineItemReviewState(item);
  const status: StepState = reviewState === 'concept' ? 'current' : 'done';
  const detailHref = getFertilityTimelineDetailHref(item);
  return timelineItem({
    title: item.titel,
    meta: `${item.datum} · ${item.label} · ${item.bron}`,
    detail: item.detail,
    state: status,
    className: 'fertility-timeline-item',
    data: {
      'timeline-item-kind': item.soort,
      'timeline-item-state': reviewState === 'concept' ? 'concept' : 'reviewed',
    },
    body: `
      ${item.eigenaar ? `<small>Eigenaar: ${escapeHtml(item.eigenaar)}</small>` : ''}
      <small>Status: ${escapeHtml(reviewState === 'concept' ? 'conceptreview' : 'gereviewd')}</small>
      ${
        item.aanbevelingFeedbackStatus
          ? `<small data-timeline-recommendation-feedback-status="${escapeAttribute(item.aanbevelingFeedbackStatus)}">Feedback: ${escapeHtml(FERTILITY_TIMELINE_AANBEVELING_FEEDBACK_LABELS[item.aanbevelingFeedbackStatus])}</small>`
          : item.soort === 'aanbeveling'
            ? '<small data-timeline-recommendation-feedback-status="geen">Feedback: nog niet gemarkeerd</small>'
            : ''
      }
      ${item.trajectId ? `<small>Traject: ${escapeHtml(item.trajectId)}</small>` : ''}
      <details class="timeline-detail-drawer" data-fertility-timeline-detail-drawer="ready" data-fertility-timeline-detail-review="${escapeAttribute(reviewState)}">
        <summary>
          <span>Bron en review</span>
          <small>${escapeHtml(item.historischConcept ? 'concept controleren' : 'broncontext')}</small>
        </summary>
        <dl class="timeline-detail-drawer__facts">
          <div><dt>Bron</dt><dd>${escapeHtml(item.bron)}</dd></div>
          <div><dt>Bronverwijzingen</dt><dd>${renderFertilityTimelineBronverwijzingen(item)}</dd></div>
          <div><dt>Context</dt><dd>${escapeHtml(item.context)}</dd></div>
          <div><dt>Record-ID</dt><dd>${escapeHtml(item.recordId)}</dd></div>
          ${
            item.historischConcept
              ? `
                <div><dt>Historische reconstructie</dt><dd>${escapeHtml(item.historischConcept.reviewStatus)} · ${escapeHtml(item.historischConcept.datumBron)} · confidence ${escapeHtml(item.historischConcept.confidenceLabel)} (${Math.round(item.historischConcept.confidenceScore * 100)}%)</dd></div>
                ${
                  item.historischConcept.conflict
                    ? `<div><dt>Datumconflict</dt><dd>${escapeHtml(item.historischConcept.conflict.formulierDatum)} vs ${escapeHtml(item.historischConcept.conflict.metadataDatum)} · ${escapeHtml(item.historischConcept.conflict.toelichting)}</dd></div>`
                    : ''
                }
              `
              : ''
          }
        </dl>
        <p class="timeline-detail-drawer__review-cue">Controleer of corrigeer dit concept in het gekoppelde bronrecord; Kiempad toont hier alleen metadata en samenvatting.</p>
        <a class="inline-action timeline-detail-drawer__action" href="${detailHref}">Controleer bronrecord</a>
        ${
          item.gekoppeldeRecords.length > 0
            ? `<ul class="linked-record-list">
                ${item.gekoppeldeRecords
                  .map(
                    (record) => `
                      <li>
                        <span>${escapeHtml(FERTILITY_TIMELINE_RECORD_LABELS[record.soort])}</span>
                        <strong>${escapeHtml(record.label)}</strong>
                        <small>${escapeHtml(record.id)}</small>
                      </li>
                    `,
                  )
                  .join('')}
              </ul>`
            : renderEmptyState('Geen gekoppelde records.', { title: 'Geen koppelingen' })
        }
      </details>
    `,
  });
}

function bepaalFertilityTimelineItemReviewState(
  item: FertilityTimeline['items'][number],
): 'concept' | 'gereviewd' {
  if (item.historischConcept && item.historischConcept.reviewStatus !== 'bevestigd') {
    return 'concept';
  }
  return item.bronverwijzingen.some((bron) => bron.reviewStatus === 'concept')
    ? 'concept'
    : 'gereviewd';
}

function getFertilityTimelineDetailHref(item: FertilityTimeline['items'][number]): string {
  if (item.soort === 'onderzoek' || item.soort === 'embryo' || item.soort === 'consult') {
    return '#dossier?route=timeline';
  }
  if (item.soort === 'research') return '#kennis?route=bibliotheek';
  if (item.soort === 'vraag') return '#vragen?route=open';
  if (item.soort === 'medicatie') return '#medicatie?route=vandaag';
  if (item.soort === 'aanbeveling') return '#start-recommendations';
  return '#traject?route=context';
}

function renderFertilityTimelineGroupedItems(timeline: FertilityTimeline): string[] {
  const itemsById = new Map(timeline.items.map((item) => [item.id, item]));
  return timeline.maandGroepen.flatMap((groep) => [
    renderFertilityTimelineMonthGroup(groep),
    ...groep.itemIds
      .map((itemId) => itemsById.get(itemId))
      .filter((item): item is FertilityTimeline['items'][number] => Boolean(item))
      .map(renderFertilityTimelineItem),
  ]);
}

function renderFertilityTimelineMonthGroup(
  groep: FertilityTimeline['maandGroepen'][number],
): string {
  const bronLabel = groep.bronnen.length === 1 ? '1 bron' : `${groep.bronnen.length} bronnen`;
  const reviewLabel =
    groep.conceptCount > 0
      ? `${groep.conceptCount} conceptreview${groep.conceptCount === 1 ? '' : 's'} via Details`
      : 'review klaar';
  return `
    <li class="fertility-timeline-month-group" data-fertility-timeline-month="${escapeAttribute(groep.maand)}" data-fertility-timeline-month-review="${escapeAttribute(groep.reviewStatussen.join(' '))}">
      <div>
        <span>${escapeHtml(groep.label)}</span>
        <strong>${groep.itemCount} moment${groep.itemCount === 1 ? '' : 'en'}</strong>
      </div>
      <p>${escapeHtml(groep.datumVanaf)} t/m ${escapeHtml(groep.datumTot)} · ${escapeHtml(bronLabel)} · ${escapeHtml(reviewLabel)}</p>
    </li>
  `;
}

function renderFertilityTimelineBronverwijzingen(item: FertilityTimeline['items'][number]): string {
  if (item.bronverwijzingen.length === 0) return 'Geen bronverwijzingen gekoppeld.';

  return item.bronverwijzingen
    .map(
      (bron) =>
        `${bron.label}: ${bron.bron} · Datum: ${bron.datum} · Review: ${bron.reviewStatus} · Record: ${bron.recordId}`,
    )
    .map(escapeHtml)
    .join(' | ');
}

const FERTILITY_TIMELINE_RECORD_LABELS: Record<FertilityTimelineRecordKoppeling['soort'], string> =
  {
    traject: 'Traject',
    afspraak: 'Afspraak',
    dossier: 'Dossierrecord',
    consult: 'Consultverslag',
    vraag: 'Vraag',
    medicatie: 'Medicatie',
    doseLog: 'Medicatiemoment',
    kennis: 'Kennisitem',
    aanbeveling: 'Suggestie',
  };

function bouwTrajectGraphWeergave(
  state: AppShellState,
  fallbackTrajectId: string | undefined,
): FertilityGraphTrajectWeergave | undefined {
  const trajectId = state.graphFilter?.trajectId ?? fallbackTrajectId;
  if (!trajectId) return undefined;

  const vandaag = new Date().toISOString().slice(0, 10);
  const aanbevelingen = bouwDagelijksAanbevelingsoverzicht({
    datum: vandaag,
    afspraken: state.afspraken.map((bundle) => bundle.afspraak),
    medicatie: state.medicatie,
    vragen: state.vragen.map((bundle) => bundle.vraag),
    consultVerslagen: state.consultVerslagen ?? [],
    trajecten: state.trajecten,
    dossierDocuments: state.dossierDocuments ?? [],
    cycleData: state.cycleData ?? [],
  });
  const rebuild = herbouwFertilityGraphIndex({
    trajecten: state.trajecten,
    afspraken: state.afspraken.map((bundle) => bundle.afspraak),
    dossierDocuments: state.dossierDocuments ?? [],
    consultVerslagen: state.consultVerslagen ?? [],
    kennisItems: state.kennisItems,
    aanbevelingen,
  });

  const weergave = bouwFertilityGraphWeergavePerTraject(rebuild.graph, {
    trajectId,
    relatieType: parseFertilityGraphRelatieType(state.graphFilter?.relatieType),
    datumVanaf: state.graphFilter?.datumVanaf,
    datumTot: state.graphFilter?.datumTot,
  });

  return {
    ...weergave,
    rebuildRapport: rebuild.rapport,
  };
}

